def analyze_data(data: List[Dict[str, Any]], threshold: float) -> Dict[str, Any]:
    def _validate(item: Dict[str, Any]) -> bool:
        if not isinstance(item, dict):
            return False
        if "value" not in item:
            return False
        try:
            val = float(item["value"])
        except (TypeError, ValueError):
            return False
        return val >= threshold

    high: List[Dict[str, Any]] = []
    low: List[Dict[str, Any]] = []
    for entry in data:
        if _validate(entry):
            high.append(entry)
        else:
            low.append(entry)
    return {"high": high, "low": low, "counts": {"high": len(high), "low": len(low)}}

