    source: AsyncIterator[Any],
    batch_size: int = 10,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    batch: List[Any] = []
    async def _fetch() -> None:
        nonlocal batch
        try:
            async for item in source:
                batch.append(item)
                if len(batch) >= batch_size:
                    break
        except Exception as exc:
            errors.append(str(exc))
    async def _process(batch_items: List[Any]) -> Dict[str, Any]:
        processed: Dict[str, Any] = {}
        for idx, itm in enumerate(batch_items):
            try:
                processed[f"item_{idx}"] = itm
            except Exception as exc:
                errors.append(f"process error {idx}: {exc}")
        return processed
    try:
        await asyncio.wait_for(_fetch(), timeout=timeout)
    except asyncio.TimeoutError:
        errors.append("fetch timeout")
    if batch:
        proc = await _process(batch)
        results.append(proc)
    return {
        "results": results,
        "errors": errors,
    }

