async def process_data(
    items: Iterable[Dict[str, Any]],
    key: str,
    threshold: Union[int, float],
    *,
    max_items: Optional[int] = None,
    timeout: float = 2.0,
) -> Dict[str, Any]:
    # Validate parameters
    if not isinstance(items, Iterable):
        raise TypeError("items must be an iterable of dicts")
    if not isinstance(key, str):
        raise TypeError("key must be a string")
    if not isinstance(threshold, (int, float)):
        raise TypeError("threshold must be numeric")
    if max_items is not None and not isinstance(max_items, int):
        raise TypeError("max_items must be an int or None")
    if not isinstance(timeout, (int, float)):
        raise TypeError("timeout must be numeric")
    results: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    processed = 0


    async def _inner() -> None:
        nonlocal processed
        for item in items:
            if not isinstance(item, dict):
                continue
            val = item.get(key)
            try:
                num = float(val)
            except (TypeError, ValueError):
                continue
            if num >= threshold:
                key_name = str(val).strip()
                counts[key_name] = counts.get(key_name, 0) + 1
                results.append(dict(item))
                processed += 1
                if max_items is not None and processed >= max_items:
                    break
    try:
        await asyncio.wait_for(_inner(), timeout=timeout)
    except asyncio.TimeoutError:
        return {"error": "timeout", "items": results, "counts": counts}
    return {"items": results, "counts": counts, "processed": processed}

