from typing import Any, AsyncIterator, Dict, List, Optional, Tuple
async def process_stream(
    source: AsyncIterator[Dict[str, Any]],
    batch_size: int,
    max_retries: int = 3,
    timeout: float = 5.0,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    results: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {"batches": 0, "errors": 0}
    async def _fetch_batch() -> List[Dict[str, Any]]:
        batch: List[Dict[str, Any]] = []
        try:
            for _ in range(batch_size):
                item = await source.__anext__()
                batch.append(item)
        except StopAsyncIteration:
            pass
        except Exception:
            stats["errors"] += 1
        return batch
    async def _process_item(item: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        for attempt in range(max_retries):
            try:
                await asyncio.sleep(0.1)
                if item.get("valid", False):
                    return item
                else:
                    raise ValueError("invalid")
            except Exception:
                if attempt == max_retries - 1:
                    stats["errors"] += 1
                    return None
                await asyncio.sleep(0.2)
        return None
    async def _process_batch(batch: List[Dict[str, Any]]) -> None:
        for item in batch:
            processed = await _process_item(item)
            if processed is not None:
                results.append(processed)
    try:
        while True:
            batch = await asyncio.wait_for(_fetch_batch(), timeout=timeout)
            if not batch:
                break
            stats["batches"] += 1
            await _process_batch(batch)
    except asyncio.TimeoutError:
        stats["errors"] += 1
    return results, stats

