from typing import Any, AsyncIterator, Dict, List, Optional, Tuple
async def process_stream(
    stream: AsyncIterator[int],
    batch_size: int,
    transform: Optional[Any] = None,
    timeout: float = 2.0,
) -> Dict[str, Any]:
    results: List[List[int]] = []
    current_batch: List[int] = []
    errors: List[str] = []

    async def _fetch() -> None:
        nonlocal current_batch
        try:
            async for item in stream:
                current_batch.append(int(item))
                if len(current_batch) >= batch_size:
                    results.append(current_batch)
                    current_batch = []
        except Exception as e:
            errors.append(str(e))

    async def _finalize() -> None:
        if current_batch:
            results.append(current_batch)

    async def _apply_transform() -> None:
        if transform is None:
            return
        for i, batch in enumerate(results):
            try:
                results[i] = [transform(x) for x in batch]
            except Exception as e:
                errors.append(f"transform error in batch {i}: {e}")

    try:
        await asyncio.wait_for(_fetch(), timeout=timeout)
    except asyncio.TimeoutError:
        errors.append("timeout reached while fetching")
    finally:
        await _finalize()

    await _apply_transform()

    return {
        "batches": results,
        "errors": errors,
    }

