def process_items(items: List[Dict[str, Any]], key: str, threshold: float) -> Dict[str, Any]:
    def _convert(val: Any) -> float:
        try:
            return float(val)
        except (TypeError, ValueError):
            return 0.0

    filtered: List[Dict[str, Any]] = []
    stats: Dict[str, float] = {"count": 0.0, "sum": 0.0, "max": float("-inf"), "min": float("inf")}

    for item in items:
        if not isinstance(item, dict):
            continue
        val = _convert(item.get(key))
        if val >= threshold:
            filtered.append(item)
            stats["count"] += 1
            stats["sum"] += val
            if val > stats["max"]:
                stats["max"] = val
            if val < stats["min"]:
                stats["min"] = val

    return {"filtered": filtered, "stats": stats}

