from typing import Any, Dict, List, Optional

async def process_numbers(nums: List[int], threshold: int = 10) -> Dict[str, Any]:
    if not isinstance(nums, list):
        return {"error": "nums must be a list", "result": None}

    def _filter_and_sum(values: List[int]) -> int:
        total = 0
        for v in values:
            if isinstance(v, int) and v >= threshold:
                total += v
        return total

    async def _async_compute() -> int:
        await asyncio.sleep(0.1)
        return _filter_and_sum(nums)

    def _log(msg: str) -> None:
        print(f"[process_numbers] {msg}")

    try:
        result = await _async_compute()
        _log(f"Computed sum {result}")
    except Exception as e:
        return {"error": str(e), "result": None}

    return {"result": result, "count": len(nums), "threshold": threshold}

from typing import Any, Dict, List, Optional, Tuple


def process_data(data: List[Dict[str, Any]]) -> Tuple[Dict[str, int], List[Dict[str, Any]]]:
    def _normalize_status(item: Dict[str, Any]) -> Optional[str]:
        status = item.get("status")
        if status is None:
            return None
        return str(status).strip().lower()

    counts: Dict[str, int] = {}
    valid_items: List[Dict[str, Any]] = []

    for entry in data:
        if not isinstance(entry, dict):
            continue
        status = _normalize_status(entry)
        if status is None:
            continue
        counts[status] = counts.get(status, 0) + 1
        valid_items.append(entry)

    return counts, valid_items

