from typing import Any, Dict, List, Optional
async def fetch_and_process(urls: List[str], max_concurrent: int = 5) -> Dict[str, Any]:
    if not urls:
        return {"error": "no URLs provided", "results": {}}
    semaphore = asyncio.Semaphore(max_concurrent)
    results: Dict[str, Any] = {}
    errors: List[str] = []
    async def _fetch(session: aiohttp.ClientSession, url: str) -> Optional[str]:
        async with semaphore:
            try:
                async with session.get(url, timeout=10) as resp:
                    if resp.status == 200:
                        return await resp.text()
                    else:
                        errors.append(f"{url} returned {resp.status}")
                        return None
            except Exception as exc:
                errors.append(f"{url} error: {exc}")
                return None
    async with aiohttp.ClientSession() as session:
        tasks = [asyncio.create_task(_fetch(session, u)) for u in urls]
        responses = await asyncio.gather(*tasks)
    for url, content in zip(urls, responses):
        if content is not None:
            results[url] = {"length": len(content), "preview": content[:100]}
    return {"results": results, "errors": errors}

