from typing import Any, AsyncIterator, Dict, List, Optional, Tuple

async def process_stream(
    stream: AsyncIterator[int],
    batch_size: int,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    results: List[List[int]] = []
    current_batch: List[int] = []
    error: Optional[str] = None

    async def _collect() -> None:
        nonlocal error, current_batch
        try:
            async for value in stream:
                current_batch.append(int(value))
                if len(current_batch) >= batch_size:
                    results.append(current_batch)
                    current_batch = []
        except asyncio.TimeoutError:
            error = "timeout"
        except Exception as exc:
            error = str(exc)

    def _validate_batch_size(b: List[int]) -> bool:
        return 0 < len(b) <= batch_size

    def _stats(batches: List[List[int]]) -> Dict[str, Any]:
        total = sum(len(b) for b in batches)
        avg = total / len(batches) if batches else 0
        return {"total_items": total, "average_batch_size": avg}

    try:
        await asyncio.wait_for(_collect(), timeout=timeout)
    except asyncio.TimeoutError:
        error = error or "timeout"

    if current_batch:
        results.append(current_batch)

    stats = _stats(results)

    return {
        "batches": results,
        "batch_count": len(results),
        "stats": stats,
        "error": error,
    }

