            continue
        if not _filter(rec):
            continue
        rec_copy = dict(rec)
        rec_copy["category"] = _normalize(rec_copy.get("category"))
        filtered.append(rec_copy)
        cat = rec_copy["category"]
        counts[cat] = counts.get(cat, 0) + 1

    filtered.sort(key=lambda r: r.get("score", 0), reverse=True)
    return filtered, counts


