from typing import Any, AsyncIterator, Dict, List, Optional
async def process_data(
    stream: AsyncIterator[Dict[str, Any]],
    batch_size: int,
    max_retries: int = 3,
) -> List[Dict[str, Any]]:
    results: List[Dict[str, Any]] = []
    async def _fetch_batch() -> List[Dict[str, Any]]:
        batch: List[Dict[str, Any]] = []
        try:
            async for _ in range(batch_size):
                item = await stream.__anext__()
                batch.append(item)
        except StopAsyncIteration: pass
        except Exception: raise
        return batch
    async def _retry(fn, *args, **kwargs):
        for attempt in range(1, max_retries + 1): try:
            return await fn(*args, **kwargs)
        except Exception:
            if attempt == max_retries:
                raise
            await asyncio.sleep(2 ** attempt)
    async def _process_item(item: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        if not isinstance(item, dict):
            return None
        value = item.get("value")
        if value is None:
            return None
        try:
            processed = int(value) * 2
        except Exception:
            return None
        return {"original": item, "processed": processed}
    while True:
        batch = await _fetch_batch()
        if not batch:
            break
        for item in batch:
            processed = await _retry(_process_item, item)
            if processed:
                results.append(processed)
    return results

