    def _is_valid_url(u: str) -> bool:
        return u.startswith("http://") or u.startswith("https://")

    if not urls:
        return {"success": [], "failure": [{"error": "no urls provided"}]}

    urls = [u for u in urls if _is_valid_url(u)]
    if not urls:
        return {"success": [], "failure": [{"error": "no valid urls"}]}

    async def _fetch(session: aiohttp.ClientSession, url: str) -> None:
        try:
            async with session.get(url, timeout=timeout) as resp:
                if resp.status == 200:
                    data = await resp.json()
                    results["success"].append({"url": url, "data": data})
                else:
                    results["failure"].append({"url": url, "status": resp.status})
        except asyncio.TimeoutError:
            results["failure"].append({"url": url, "error": "timeout"})
        except Exception as e:
            results["failure"].append({"url": url, "error": str(e)})

    async with aiohttp.ClientSession() as session:
        tasks = [_fetch(session, u) for u in urls]
        await asyncio.gather(*tasks)

    return results

