    max_items: int,
    timeout: float = 5.0,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    # Validate parameters
    if max_items <= 0:
        raise ValueError("max_items must be positive")
    if timeout <= 0:
        raise ValueError("timeout must be positive")
    results: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    errors: List[str] = []
    async def _extract_key(item: Dict[str, Any]) -> Optional[str]:
