        if isinstance(key, str):
            return key.strip().lower()
        return None
    async def _process_item(item: Dict[str, Any]) -> None:
        key = await _extract_key(item)
        if key:
            counts[key] = counts.get(key, 0) + 1
            results.append(item)
        else:
            errors.append("missing or invalid type key")
    async def _consume() -> None:
        try:
            async for idx, item in enumerate(source, start=1):
                await _process_item(item)
                if idx >= max_items:
                    break
        except asyncio.TimeoutError:
            errors.append("timeout")
        except Exception as exc:
            errors.append(str(exc))
    try:
        await asyncio.wait_for(_consume(), timeout=timeout)
    except asyncio.TimeoutError:
        errors.append("overall timeout")
    return results, counts

