from typing import Any, AsyncIterator, Dict, List, Tuple
async def process_stream(
    stream: AsyncIterator[Dict[str, Any]],
    key: str,
    threshold: float,
    max_items: int = 1000,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {"count": 0, "sum": 0.0, "max": None, "min": None, "errors": 0}
    async def _validate(item: Dict[str, Any]) -> bool:
        if not isinstance(item, dict) or key not in item:
            return False
        try:
            val = float(item[key])
        except (TypeError, ValueError):
            return False
        return val >= threshold
    async def _process(item: Dict[str, Any]) -> None:
        nonlocal stats
        val = float(item[key])
        stats["count"] += 1
        stats["sum"] += val
        if stats["max"] is None or val > stats["max"]:
            stats["max"] = val
        if stats["min"] is None or val < stats["min"]:
            stats["min"] = val
        results.append(item)
    async def _consume() -> None:
        async for item in stream:
            if len(results) >= max_items:
                break
            if await _validate(item):
                await _process(item)
            else:
                stats["errors"] += 1
    try:
        await _consume()
    except Exception:
        stats["errors"] += 1
    return {"results": results, "stats": stats}

