async def process_records(
    stream: AsyncIterator[Dict[str, Any]],
    required_fields: List[str],
    max_records: int = 1000,
    timeout: float = 5.0,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    records: List[Dict[str, Any]] = []
    errors: List[str] = []
    seen_keys: Dict[str, int] = {}

    def _validate(rec: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in rec:
                errors.append(f"missing {field}")
                return False
        return True

    async def _consume() -> None:
        nonlocal records
        try:
            async for rec in stream:
                if not isinstance(rec, dict):
                    errors.append("record not a dict")
                    continue
                if not _validate(rec):
                    continue
                key = rec.get("id")
                if key is None:
                    errors.append("no id field")
                    continue
                seen_keys[key] = seen_keys.get(key, 0) + 1
                records.append(rec)
                if len(records) >= max_records:
                    break
        except asyncio.TimeoutError:
            errors.append("timeout during consumption")
        except Exception as e:
            errors.append(str(e))

    try:
        await asyncio.wait_for(_consume(), timeout=timeout)
    except asyncio.TimeoutError:
        errors.append("overall timeout")

    return records, seen_keys

