    threshold: float = 0.5,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    results: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {"count": 0, "sum": 0.0, "max": None, "min": None}

    def _update_stats(val: float) -> None:
        stats["count"] += 1
        stats["sum"] += val
        if stats["max"] is None or val > stats["max"]:
            stats["max"] = val
        if stats["min"] is None or val < stats["min"]:
            stats["min"] = val

    async def _consume() -> None:
        async for item in data:
            if not isinstance(item, dict):
                continue
            if key not in item:
                continue
            try:
                val = float(item[key])
            except (TypeError, ValueError):
                continue
            if val < threshold:
                continue
            _update_stats(val)
            results.append(item)
            if len(results) >= limit:
                break

    try:
        await _consume()
    except Exception as e:
        stats["error"] = str(e)

    if stats["count"] > 0:
        stats["average"] = stats["sum"] / stats["count"]
    else:
        stats["average"] = None

    return results, stats

