async def async_process_items(
    source: AsyncIterator[Dict[str, Any]],
    key: str,
    threshold: float,
    batch_size: int = 10,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    batch: List[Dict[str, Any]] = []
    def _extract_value(item: Dict[str, Any]) -> Optional[float]:
        try:
            return float(item.get(key, 0))
        except (TypeError, ValueError):
            return None
    async def _fetch_batch() -> None:
        nonlocal batch
        try:
            async for _ in range(batch_size):
                try:
                    item = await source.__anext__()
                except StopAsyncIteration:
                    return
                val = _extract_value(item)
                if val is not None:
                    batch.append(item)
        except Exception as e:
            errors.append(str(e))
    async def _process_batch() -> None:
        nonlocal batch
        for itm in batch:
            val = _extract_value(itm)
            if val is not None and val >= threshold:
                results.append(itm)
        batch = []
    try:
        await asyncio.wait_for(_fetch_batch(), timeout=timeout)
        await _process_batch()
    except asyncio.TimeoutError:
        errors.append("timeout")
    except Exception as e:
        errors.append(str(e))
    return {"results": results, "errors": errors, "count": len(results)}

