from typing import Any, Dict, List

async def fetch_and_process(urls: List[str], timeout: float = 5.0) -> Dict[str, Any]:
    results: Dict[str, Any] = {}
    errors: List[str] = []

    async def _fetch(url: str) -> str:
        async with aiohttp.ClientSession() as session:
            async with session.get(url, timeout=timeout) as resp:
                if resp.status != 200:
                    raise ValueError(f\"{url} returned {resp.status}\")
                return await resp.text()

    async def _process(content: str, url: str) -> None:
        word_count = len(content.split())
        results[url] = word_count

    tasks = []
    for url in urls:
        tasks.append((url, asyncio.create_task(_fetch(url))))

    for url, task in tasks:
        try:
            content = await task
            await _process(content, url)
        except Exception as e:
            errors.append(f\"{url}: {e}\")

    return {"results": results, "errors": errors}

import asyncio
from typing import Any, AsyncIterator, Dict, List

async def process_stream(
    stream: AsyncIterator[Dict[str, Any]],
    key: str,
    threshold: float,
    max_items: int = 100,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    stats: Dict[str, int] = {"total": 0, "accepted": 0, "rejected": 0}
    errors: List[str] = []
    def _validate(item: Dict[str, Any]) -> bool:
        if not isinstance(item, dict):
            errors.append("item not dict")
            return False
        if key not in item:
            errors.append(f"missing key {key}")
            return False
        try:
            value = float(item[key])
        except (TypeError, ValueError):
            errors.append(f"invalid value for {key}")
            return False
        return value >= threshold
    async def _consume() -> None:
        async for raw in stream:
            stats["total"] += 1
            if len(results) >= max_items:
                break
            if _validate(raw):
                results.append(raw)
                stats["accepted"] += 1
            else:
                stats["rejected"] += 1
    try:
        await _consume()
    except Exception as exc:
        errors.append(str(exc))

    return {"results": results, "stats": stats, "errors": errors}

import re
from typing import Any, AsyncIterator, Dict, List, Optional
async def process_stream(
    stream: AsyncIterator[str],
    pattern: str,
    max_items: int = 100,
) -> Dict[str, Any]:
    compiled = re.compile(pattern)

    def _match(line: str) -> bool:
        return bool(compiled.search(line))
    async def _collect() -> List[str]:
        collected: List[str] = []
        async for line in stream:
            if _match(line):
                collected.append(line)
                if len(collected) >= max_items:
                    break
        return collected
    try:
        results = await _collect()
    except Exception as exc:
        return {
            "error": str(exc),
            "matched": [],
            "count": 0,
        }
    return {
        "matched": results,
        "count": len(results),
        "pattern": pattern,
    }

