from typing import Any, AsyncIterator, Dict, List, Optional, Tuple
async def process_stream(
    source: AsyncIterator[Dict[str, Any]],
    max_items: int,
    filter_key: str = "active",
    filter_value: Any = True,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    async def _fetch() -> List[Dict[str, Any]]:
        items: List[Dict[str, Any]] = []
        try:
            async for item in source:
                items.append(item)
                if len(items) >= max_items:
                    break
        except asyncio.TimeoutError:
            pass
        return items

    def _filter(items: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return [i for i in items if i.get(filter_key) == filter_value]

    def _aggregate(items: List[Dict[str, Any]]) -> Dict[str, Any]:
        counts: Dict[str, int] = {}
        for i in items:
            for k, v in i.items():
                if isinstance(v, str):
                    counts[k] = counts.get(k, 0) + 1
        return counts

    try:
        raw_items = await asyncio.wait_for(_fetch(), timeout=timeout)
    except asyncio.TimeoutError:
        raw_items = []

    filtered = _filter(raw_items)
    stats = _aggregate(filtered)

    return {"total_fetched": len(raw_items), "total_filtered": len(filtered), "stats": stats, "error": None if raw_items else "timeout or empty source"}

