from typing import Any, AsyncIterator, Dict, List, Optional, Tuple

async def async_process_stream(
    stream: AsyncIterator[Dict[str, Any]],
    filter_key: str,
    threshold: float,
    max_items: int,
    timeout: float = 5.0,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    results: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {"count": 0, "sum": 0.0}
    error: Optional[str] = None

    async def _filter(item: Dict[str, Any]) -> bool:
        try:
            val = float(item.get(filter_key, 0))
        except (TypeError, ValueError):
            return False
        return val > threshold

    async def _collector() -> None:
        nonlocal error
        try:
            async for item in stream:
                if await _filter(item):
                    results.append(item)
                    stats["count"] += 1
                    stats["sum"] += float(item.get(filter_key, 0))
                    if stats["count"] >= max_items:
                        break
        except asyncio.TimeoutError:
            error = "timeout"
        except Exception as e:
            error = str(e)

    try:
        await asyncio.wait_for(_collector(), timeout=timeout)
    except asyncio.TimeoutError:
        error = error or "timeout"

    def _average() -> float:
        if stats["count"] == 0:
            return 0.0
        return stats["sum"] / stats["count"]

    stats["average"] = _average()

    return results, {"stats": stats, "error": error}

