import asyncio
from typing import Any, AsyncIterator, Dict, List, Optional, Tuple
async def fetch_and_process(
    urls: List[str],
    process: Any,
    max_concurrent: int = 5,
    timeout: float = 10.0,
) -> Dict[str, Any]:
    results: Dict[str, Any] = {}
    errors: List[str] = []
    semaphore = asyncio.Semaphore(max_concurrent)
    async def _fetch(url: str) -> Tuple[str, Optional[str]]:
        try:
            async with semaphore:
                await asyncio.sleep(0.1)  # simulate network delay
                return url, f"data from {url}"
        except Exception as e:
            return url, None
    async def _worker(url: str) -> None:
        url, data = await _fetch(url)
        if data is None:
            errors.append(f"Failed to fetch {url}")
        else:
            try:
                results[url] = process(data)
            except Exception as e:
                errors.append(f"Processing error for {url}: {e}")
    tasks = [_worker(u) for u in urls]
    await asyncio.gather(*tasks)
    return {
        "results": results,
        "errors": errors,
    }

