async def process_records(
    stream: AsyncIterator[Dict[str, Any]],
    threshold: float,
    max_items: int,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    count = 0

    def _validate(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if "value" not in rec:
            return False
        try:
            val = float(rec["value"])
        except (TypeError, ValueError):
            return False
        return val >= threshold

    async def _process() -> None:
        nonlocal count
        async for rec in stream:
            if count >= max_items:
                break
            if not _validate(rec):
                errors.append(f"invalid record at {count}")
                continue
            transformed = {"id": rec.get("id"), "value": float(rec["value"]) }
            results.append(transformed)
            count += 1

    try:
        await asyncio.wait_for(_process(), timeout=5.0)
    except asyncio.TimeoutError:
        errors.append("processing timed out")


    return {
        "records": results,
        "errors": errors,
        "count": count,
    }

