async def process_stream(
    stream: AsyncIterator[Any],
    max_items: int,
    filter_func: Optional[Any] = None,
) -> Dict[str, Any]:

    def _apply(item: Any) -> bool:
        if filter_func is None:
            return True
        try:
            return bool(filter_func(item))
        except Exception:
            return False

    collected: List[Any] = []
    errors: List[str] = []

    async for idx, item in enumerate(stream, start=1):
        try:
            if _apply(item):
                collected.append(item)
                if len(collected) >= max_items:
                    break
        except Exception as exc:
            errors.append(str(exc))


    return {
        "collected": collected,
        "count": len(collected),
        "errors": errors,
        "total_processed": idx,
    }

