async def process_data(
    source: AsyncIterator[Dict[str, Any]],
    key: str,
    threshold: float,
    max_items: int = 100,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    stats: Dict[str, int] = {"count": 0, "filtered": 0}
    error: Optional[str] = None

    def _extract_value(item: Dict[str, Any]) -> Optional[float]:
