def process_items(items: List[Dict[str, Any]], threshold: float) -> Dict[str, Any]:
    result: Dict[str, Any] = {\"above\": [], \"below\": [], \"counts\": {\"above\": 0, \"below\": 0}}
    for item in items:
        if not isinstance(item, dict):
            continue
        value = item.get(\"value\")
        try:
            val = float(value)
        except (TypeError, ValueError):
            continue
        if val >= threshold:
            result[\"above\"].append(item)
            result[\"counts\"][\"above\"] += 1
        else:
            result[\"below\"].append(item)
            result[\"counts\"][\"below\"] += 1
    result[\"summary\"] = f\"{result['counts']['above']} above, {result['counts']['below']} below\"
    return result

import asyncio
from typing import Any, AsyncIterator, Dict, List, Optional, Tuple
async def process_stream(
    source: AsyncIterator[Dict[str, Any]],
    max_items: int,
    filter_key: str = "active",
    filter_value: Any = True,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    def _normalize(item: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        if not isinstance(item, dict):
            return None
        val = item.get(filter_key)
        if val != filter_value:
            return None
        if "id" not in item or "value" not in item:
            return None
        return {"id": item["id"], "value": item["value"]}
    collected: List[Dict[str, Any]] = []
    errors: List[str] = []
    async def _consume() -> None:
        try:
            async for raw in source:
                norm = _normalize(raw)
                if norm is not None:
                    collected.append(norm)
                    if len(collected) >= max_items:
                        break
        except asyncio.TimeoutError:
            errors.append("timeout")
        except Exception as exc:
            errors.append(str(exc))
    try:
        await asyncio.wait_for(_consume(), timeout=timeout)
    except asyncio.TimeoutError:
        errors.append("overall_timeout")
    return {
        "items": collected,
        "count": len(collected),
        "errors": errors,
    }

import asyncio
from typing import Any, Dict, List, Optional
async def process_items(items: List[Dict[str, Any]], threshold: float) -> Dict[str, Any]:
    if not isinstance(items, list):
        return {"error": "items must be a list", "processed": [], "failed": 0}
    processed: List[Dict[str, Any]] = []
    failed: int = 0
    async def _process(item: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        if not isinstance(item, dict):
            return None
        value = item.get("value")
        if value is None:
            return None
        try:
            val = float(value)
        except (TypeError, ValueError):
            return None
        if val < threshold:
            return None
        await asyncio.sleep(0.01)
        return {"id": item.get("id"), "value": val}
    tasks = [_process(it) for it in items]
    results = await asyncio.gather(*tasks, return_exceptions=True)
    for res in results:
        if isinstance(res, Exception):
            failed += 1
        elif res is None:
            failed += 1
        else:
            processed.append(res)
    return {
        "processed_count": len(processed),
        "failed_count": failed,
        "items": processed
    }

