async def stream_processor(
    stream: AsyncIterator[Dict[str, Any]],
    key: str,
    threshold: float,
    max_items: int = 100,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    stats: Dict[str, int] = {"processed": 0, "filtered": 0, "errors": 0}
    error_msg: Optional[str] = None
    def _validate(item: Dict[str, Any]) -> bool:
        if not isinstance(item, dict):
            return False
        if key not in item:
            return False
        try:
            val = float(item[key])
        except (TypeError, ValueError):
            return False
        return val >= threshold

    async def _consume() -> None:
        nonlocal error_msg
        try:
            async for item in stream:
                stats["processed"] += 1
                if not _validate(item):
                    stats["filtered"] += 1
                    continue
                results.append(item)
                if len(results) >= max_items:
                    break
        except asyncio.TimeoutError:
            error_msg = "stream timeout"
        except Exception as e:
            error_msg = str(e)

    try:
        await asyncio.wait_for(_consume(), timeout=timeout)
    except asyncio.TimeoutError:
        error_msg = error_msg or "overall timeout"

    return {
        "results": results,
        "stats": stats,
        "error": error_msg,
    }

