    async def _collector() -> None:
        nonlocal error_msg
        try:
            async for entry in stream:
                stats["processed"] += 1
                if await _filter(entry):
                    results.append(entry)
                    stats["filtered"] += 1
                if len(results) >= max_items:
                    break
        except asyncio.TimeoutError:
            error_msg = "stream timeout"
        except Exception as e:
            error_msg = str(e)

    try:
        await asyncio.wait_for(_collector(), timeout=timeout)
    except asyncio.TimeoutError:
        error_msg = error_msg or "overall timeout"

    return {
        "items": results,
        "stats": stats,
        "error": error_msg,
    }

