import aiohttp
import asyncio
from typing import Any, Dict, List
async def fetch_and_process(urls: List[str], timeout: float = 5.0) -> Dict[str, Any]:
    results: Dict[str, Any] = {}
    errors: List[str] = []
    async def _fetch(url: str) -> str:
        try:
            async with aiohttp.ClientSession() as session:
                async with session.get(url, timeout=timeout) as resp:
                    resp.raise_for_status()
                    return await resp.text()
        except Exception as e:
            return f"error:{e}"
    async def _process(content: str, url: str) -> None:
        if content.startswith("error:"):
            errors.append(f"{url} -> {content}")
        else:
            # simple processing: count words
            words = content.split()
            results[url] = len(words)
    tasks = []
    for u in urls:
        tasks.append(asyncio.create_task(_fetch(u)))
    fetched = await asyncio.gather(*tasks)
    # process results
    for u, c in zip(urls, fetched):
        await _process(c, u)

    return {"results": results, "errors": errors}

