async def filter_stream(stream: AsyncIterator[Dict[str, Any]], key: str, threshold: float, max_items: int = 50) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    stats: Dict[str, int] = {}
    errors: List[str] = []

    def _value(item: Dict[str, Any]) -> Optional[float]:
        try:
            return float(item.get(key, 0))
        except (TypeError, ValueError):
            return None

    async def _consume() -> None:
        nonlocal results, stats, errors
        count = 0
        async for entry in stream:
            val = _value(entry)
            if val is None:
                errors.append(f"invalid value: {entry}")
                continue
            if val >= threshold:
                results.append(entry)
                stats[key] = stats.get(key, 0) + 1
            count += 1
            if count >= max_items:
                break

    try: await _consume(); except Exception as exc: errors.append(str(exc))

    return {"filtered": results, "count": len(results), "stats": stats, "errors": errors}

