from typing import Any, AsyncIterator, Dict, List, Optional

async def async_group_and_filter(
    source: AsyncIterator[Dict[str, Any]],
    key: str,
    threshold: int,
    *,
    max_groups: Optional[int] = None,
) -> Dict[str, List[Dict[str, Any]]]:
    def _is_valid(item: Any) -> bool:
        if not isinstance(item, dict):
            return False
        return key in item and item[key] is not None

    groups: Dict[str, List[Dict[str, Any]]] = {}
    group_counts: Dict[str, int] = {}
    async for item in source:
        if not _is_valid(item):
            continue
        val = item[key]
        key_str = str(val).strip()
        if not key_str:
            continue
        if key_str not in groups:
            groups[key_str] = []
            group_counts[key_str] = 0
        if group_counts[key_str] >= threshold:
            continue
        groups[key_str].append(item)
        group_counts[key_str] += 1
        if max_groups is not None and len(groups) >= max_groups:
            break
    # Filter out groups that didn't reach threshold
    result: Dict[str, List[Dict[str, Any]]] = {}
    for k, lst in groups.items():
        if len(lst) >= threshold:
            result[k] = lst
    return result

