# Async collector of valid items
async def collect_valid(stream: AsyncIterator[Dict[str, Any]], limit: int, timeout: float = 1.0) -> Dict[str, Any]:
    ok: List[Dict[str, Any]] = []
    err: List[str] = []
    async def _add(item: Dict[str, Any]) -> None:
