from typing import List, Dict, Optional


def process_numbers(nums: List[int], threshold: Optional[int] = None) -> Dict[str, int]:
    def is_even(n: int) -> bool:
        return n % 2 == 0

    filtered = [n for n in nums if is_even(n)]
    if threshold is not None:
        filtered = [n for n in filtered if n >= threshold]
    total = sum(filtered)
    return {"count": len(filtered), "sum": total}

