                if len(collected) >= max_items:
                    break
        except asyncio.TimeoutError:
            error = 'timeout'
        except Exception as exc:
            error = str(exc)
    try:
        await asyncio.wait_for(_consume(), timeout=timeout)
    except asyncio.TimeoutError:
        error = error or 'timeout'
    # Sort counts by frequency descending, then key ascending
    sorted_counts = dict(sorted(counts.items(), key=lambda kv: (-kv[1], kv[0])))
    def _filter(item: Dict[str, Any]) -> bool:
        # Example filter: keep items with at least one string value longer than 3
        for v in item.values():
            if isinstance(v, str) and len(v) > 3:
                return True
        return False
    # Apply filter to collected items
    filtered = [i for i in collected if _filter(i)]
    # Compute unique keys across filtered items
    unique_keys: set = set()
    for i in filtered:
        unique_keys.update(i.keys())
    # Add count of unique keys to counts dict
    counts['unique_keys'] = len(unique_keys)
    return filtered, sorted_counts, error

