async def process_items(items: List[Dict[str, Any]], threshold: float) -> Dict[str, Any]:
    def _validate(item: Dict[str, Any]) -> bool:
        if not isinstance(item, dict):
            return False
        if "value" not in item:
            return False
        try:
            return float(item["value"]) >= threshold
        except (TypeError, ValueError):
            return False
    def _transform(item: Dict[str, Any]) -> Dict[str, Any]:
        new_item = dict(item)
        new_item["value"] = float(new_item["value"])
        new_item["processed_at"] = "now"
        return new_item
    async def _process_one(idx: int, itm: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        if not _validate(itm):
            errors.append(f"item {idx} invalid")
            return None
        try:
            await asyncio.sleep(0)  # simulate async I/O
            transformed = _transform(itm)
            return transformed
        except Exception as e:
            errors.append(f"item {idx} error: {e}")
            return None
    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    tasks = []
    for idx, itm in enumerate(items):
        tasks.append(_process_one(idx, itm))
    processed = await asyncio.gather(*tasks)
    for res in processed:
        if res is not None:
            results.append(res)
    summary = {
        "count": len(results),
        "errors": len(errors),
        "error_messages": errors,
    }
    return {"data": results, "summary": summary}

