async def async_process_stream(
    stream: AsyncIterator[Dict[str, Any]],
    key: str,
    max_items: int,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    counter: int = 0

    async def _extract(item: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        try:
            value = item[key]
            if isinstance(value, (int, float)):
                return {key: value}
            else:
                return None
        except KeyError:
            return None
        except Exception as e:
            errors.append(str(e))
            return None

    async def _consumer() -> None:
        nonlocal counter
        start_time = asyncio.get_event_loop().time()
        async for raw_item in stream:
            if counter >= max_items:
                break
            extracted = await _extract(raw_item)
            if extracted is not None:
                results.append(extracted)
                counter += 1
            if asyncio.get_event_loop().time() - start_time > timeout:
                errors.append("timeout exceeded")
                break

    try:
        await asyncio.wait_for(_consumer(), timeout=timeout + 1)
    except asyncio.TimeoutError:
        errors.append("overall timeout")
    except Exception as e:
        errors.append(f"unexpected error: {e}")

    return {"extracted": results, "count": len(results), "errors": errors}

