from typing import Any, AsyncIterator, Dict, List, Optional

async def process_stream(stream: AsyncIterator[Any], batch_size: int = 10, max_batches: int = 5, timeout: float = 2.0) -> Dict[str, Any]:
    results: List[List[Any]] = []
    errors: List[str] = []
    batch: List[Any] = []
    count = 0
    async def _fetch() -> None:
        nonlocal batch, count
        try:
            async for item in stream:
                batch.append(item)
                count += 1
                if len(batch) >= batch_size:
                    results.append(batch)
                    batch = []
                    if len(results) >= max_batches:
                        break
        except asyncio.TimeoutError:
            errors.append("timeout")
        except Exception as e:
            errors.append(str(e))
    try:
        await asyncio.wait_for(_fetch(), timeout=timeout)
    except asyncio.TimeoutError:
        errors.append("overall timeout")
    if batch:
        results.append(batch)
    return {
        "batches": results,
        "total_items": count,
        "errors": errors,
    }

