async def process_stream(
    stream: AsyncIterator[Dict[str, Any]],
    key: str,
    threshold: float,
    max_items: int = 100,
    timeout: float = 5.0,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    collected: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {"count": 0, "errors": 0, "timeout": False}

    async def _consume() -> None:
        nonlocal stats
        try:
            async for item in stream:
                stats["count"] += 1
                try:
                    value = float(item.get(key, 0))
                except (TypeError, ValueError):
                    stats["errors"] += 1
                    continue
                if value >= threshold:
                    collected.append(item)
                if len(collected) >= max_items:
                    break
        except asyncio.TimeoutError:
            stats["timeout"] = True
        except Exception:
            stats["errors"] += 1

    try:
        await asyncio.wait_for(_consume(), timeout=timeout)
    except asyncio.TimeoutError:
        stats["timeout"] = True

    # Compute average of collected values for the key
    avg: Optional[float] = None
    if collected:
        avg = sum(float(item.get(key, 0)) for item in collected) / len(collected)
    stats["average"] = avg




    return collected, stats

