                    continue
                if not await _filter(raw):
                    stats["filtered"] += 1
                    continue
                stats["count"] += 1
                results.append(raw)
                if len(results) >= max_items:
                    break
        except asyncio.TimeoutError:
            error = "timeout"
        except Exception as exc:
            error = str(exc)



    try:
        await asyncio.wait_for(_process(), timeout=timeout)
    except asyncio.TimeoutError:
        error = error or "overall timeout"
    return {
        "items": results,
        "stats": stats,
        "error": error,
    }

