from typing import Any, AsyncIterator, Dict, List, Optional

async def process_stream(
    stream: AsyncIterator[Dict[str, Any]],
    key: str,
    limit: int = 10,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    seen_keys: Dict[str, int] = {}
    async def _collect() -> None:
        try:
            async for item in stream:
                if not isinstance(item, dict):
                    errors.append("invalid item"); continue
                if key not in item:
                    errors.append(f"missing key {key}"); continue
                val = item[key]
                if not isinstance(val, (int, float)):
                    errors.append(f"non-numeric value for {key}"); continue
                results.append(item)
                seen_keys[val] = seen_keys.get(val, 0) + 1
                if len(results) >= limit:
                    break
        except Exception as e:
            errors.append(str(e))
    try:
        await asyncio.wait_for(_collect(), timeout=timeout)
    except asyncio.TimeoutError:
        errors.append("overall timeout")

    return {
        "collected": results,
        "count": len(results),
        "errors": errors,
        "key_counts": dict(sorted(seen_keys.items(), key=lambda kv: (-kv[1], kv[0]))),
    }

