                if _is_valid(entry):
                    results.append(entry)
                    stats["accepted"] += 1
                else:
                    stats["filtered"] += 1
        except Exception as exc:
            errors.append(str(exc))

    await _consume()
    return {
        "items": results,
        "stats": stats,
