from typing import Any, AsyncIterator, Dict, List, Optional, Tuple

async def aggregate_stream(
    stream: AsyncIterator[Dict[str, Any]],
    key: str,
    batch_size: int = 10,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    current_batch: List[Dict[str, Any]] = []
    error: Optional[str] = None

    def _is_valid(item: Any) -> bool:
        return isinstance(item, dict) and key in item

    async def _collect() -> None:
        nonlocal error
        try:
            async for item in stream:
                if not _is_valid(item):
                    continue
                current_batch.append(item)
                if len(current_batch) >= batch_size:
                    results.append({key: current_batch.copy()})
                    current_batch.clear()
        except asyncio.TimeoutError:
            error = "timeout"
        except Exception as exc:
            error = str(exc)

    try:
        await asyncio.wait_for(_collect(), timeout=timeout)
    except asyncio.TimeoutError:
        error = error or "timeout"

    if current_batch:
        results.append({key: current_batch.copy()})

    stats: Dict[str, int] = {
        "total_items": sum(len(batch[key]) for batch in results),
        "batch_count": len(results),
    }

    return {
        "batches": results,
        "stats": stats,
        "error": error,
    }

