from typing import Any, AsyncIterator, Dict, List, Optional, Tuple

async def process_stream(
    stream: AsyncIterator[Dict[str, Any]],
    batch_size: int = 10,
    timeout: float = 2.0,
) -> Dict[str, Any]:
    def _validate(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if "id" not in rec or "value" not in rec:
            return False
        try:
            int(rec["id"])
        except (ValueError, TypeError):
            return False
        return True
    def _transform(rec: Dict[str, Any]) -> Dict[str, Any]:
        new_rec = dict(rec)
        new_rec["value"] = float(rec["value"])
        new_rec["processed_at"] = asyncio.get_event_loop().time()
        return new_rec
    batches: List[List[Dict[str, Any]]] = []; current_batch: List[Dict[str, Any]] = []
    async def _consumer() -> None:
        nonlocal current_batch; try:
            async for item in stream:
                if not _validate(item):
                    continue
                transformed = _transform(item)
                current_batch.append(transformed)
                if len(current_batch) >= batch_size:
                    batches.append(current_batch)
                    current_batch = []
        except asyncio.TimeoutError: pass
        except Exception: pass
    try: await asyncio.wait_for(_consumer(), timeout=timeout)
    except asyncio.TimeoutError:
        if current_batch:
            batches.append(current_batch)
    result: Dict[str, Any] = {
        "batches": batches,
        "batch_count": len(batches),
        "total_records": sum(len(b) for b in batches),
    }
    return result

