async def fetch_and_process(urls: List[str], timeout: float = 5.0) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    if not urls:
        return {"results": [], "errors": ["no urls provided"]}  # early exit

    async def _fetch(url: str) -> Optional[Dict[str, Any]]:
        try:
            await asyncio.sleep(0.1)  # simulate network
            if "bad" in url:
                raise ValueError("bad url")
            return {"url": url, "status": 200, "data": f"data from {url}"}
        except Exception as e:
            errors.append(f"{url}: {e}")
            return None

    async def _worker(urls_batch: List[str]) -> None:
        tasks = [asyncio.create_task(_fetch(u)) for u in urls_batch]
        for t in tasks:
            res = await t
            if res:
                results.append(res)

    batch_size = 5
    batches = [urls[i:i+batch_size] for i in range(0, len(urls), batch_size)]

    try:
        await asyncio.wait_for(
            asyncio.gather(*( _worker(b) for b in batches )),
            timeout=timeout
        )
    except asyncio.TimeoutError:
        errors.append("overall timeout")

    summary = {
        "total": len(urls),
        "fetched": len(results),
        "errors": len(errors),
    }

    return {
        "summary": summary,
        "results": results,
        "errors": errors,
    }

