    results: List[Dict[str, Any]] = []; stats: Dict[str, int] = {"matched": 0, "skipped": 0}; error: Optional[str] = None

    def _filter(item: Dict[str, Any]) -> bool:
        try:
            val = float(item.get(key, 0))
        except (TypeError, ValueError):
            return False
        return val >= threshold

    async def _consume() -> None:
        nonlocal error
        try:
            async for entry in source:
                if _filter(entry):
                    results.append(entry); stats["matched"] += 1
                else:
                    stats["skipped"] += 1
                if len(results) >= max_items:
                    break
        except Exception as exc:
            error = str(exc)

    try:
        await asyncio.wait_for(_consume(), timeout=timeout)
    except asyncio.TimeoutError:
        error = error or "timeout"




    return {"items": results, "stats": stats, "error": error}

