async def process_data(
    data_stream: asyncio.Queue,
    max_items: int,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    collected: List[Any] = []
    errors: List[str] = []

    async def _fetch() -> None:
        nonlocal collected, errors
        try:
            while len(collected) < max_items:
                item = await asyncio.wait_for(data_stream.get(), timeout=timeout)
                if item is None:
                    continue
                try:
                    processed = _process_item(item)
                    collected.append(processed)
                except Exception as e:
                    errors.append(str(e))
        except asyncio.TimeoutError:
            errors.append("timeout")
        except Exception as e:
            errors.append(str(e))

    def _process_item(item: Any) -> Any:
        if isinstance(item, dict):
            return {k.upper(): v for k, v in item.items()}
        return str(item).upper()

    await _fetch()

    result: Dict[str, Any] = {
        "count": len(collected),
        "items": collected,
        "errors": errors,
    }
    return result

