from typing import Any, AsyncIterator, Dict, List, Optional, Tuple

async def process_stream(
    source: AsyncIterator[Dict[str, Any]],
    max_items: int,
    key: str = "value",
    threshold: float = 0.5,
    *,
    verbose: bool = False,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    collected: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    async def _validate(item: Dict[str, Any]) -> bool:
        if not isinstance(item, dict):
            return False
        if key not in item:
            return False
        try:
            val = float(item[key])
        except (TypeError, ValueError):
            return False
        return val >= threshold
    async def _process(item: Dict[str, Any]) -> None:
        nonlocal collected, counts
        if verbose:
            print(f"Processing item: {item}")
        if key in item:
            val = item[key]
            counts[val] = counts.get(val, 0) + 1
        collected.append(item)
    async def _consumer() -> None:
        async for itm in source:
            if len(collected) >= max_items:
                if verbose:
                    print("Reached max_items, stopping consumption.")
                break
            if await _validate(itm):
                await _process(itm)
            else:
                if verbose:
                    print(f"Item skipped due to validation: {itm}")
    try:
        await asyncio.wait_for(_consumer(), timeout=5.0)
    except asyncio.TimeoutError:
        if verbose:
            print("Timeout reached while consuming stream.")
    return collected, counts

