async def process_data(
    source: AsyncIterator[Dict[str, Any]],
    batch_size: int = 10,
    max_retries: int = 3,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    attempt: int = 0
    async def _fetch_batch() -> List[Dict[str, Any]]:
        batch: List[Dict[str, Any]] = []
        try:
            async for item in source:
                batch.append(item)
                if len(batch) >= batch_size:
                    break
        except Exception as e:
            raise RuntimeError(f"fetch error: {e}")
        return batch
    async def _process_batch(batch: List[Dict[str, Any]]) -> None:
        for entry in batch:
            try:
                if entry.get("status") == "error":
                    raise ValueError("entry error status")
                results.append(entry)
            except Exception as e:
                errors.append(str(e))
    while attempt < max_retries:
        try:
            batch = await asyncio.wait_for(_fetch_batch(), timeout=timeout)
            if not batch:
                break
            await _process_batch(batch)
            results.extend(batch)
            attempt = 0
        except Exception as e:
            attempt += 1
            errors.append(f"retry {attempt}/{max_retries}: {e}")
            if attempt >= max_retries:
                break
    return {
        "processed": results,
        "buffered": results,
        "errors": errors,
    }

