            val = float(item.get(key, 0))
            return val
        except (TypeError, ValueError):
            return None

    async def _process() -> None:
        nonlocal error
        try:
            async for entry in stream:
                stats["processed"] += 1
                val = await _extract_value(entry)
                if val is None:
                    continue
                if val >= threshold:
                    results.append(entry)
                    stats["filtered"] += 1
                if len(results) >= max_items:
                    break
        except asyncio.CancelledError:
            error = "cancelled"
        except Exception as exc:
            error = str(exc)
    await _process()
    return {"results": results, "stats": stats, "error": error}

