async def process_stream(
    source: AsyncIterator[Any],
    batch_size: int = 10,
    max_retries: int = 3,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    results: List[Any] = []
    errors: List[str] = []
    retries = 0

    while True:
        batch: List[Any] = []
        try:
            for _ in range(batch_size):
                item = await source.__anext__()
                batch.append(item)
        except StopAsyncIteration:
            pass
        except Exception as e:
            errors.append(str(e))
        if not batch:
