                if isinstance(item, dict) and item.get("fail"):
                    raise ValueError("Processing failed")
                results.append(item)
            except Exception as e:
                errors.append(str(e))
                retries += 1
                if retries > max_retries:
                    errors.append("max retries exceeded")
                    break
        if retries > max_retries:
            break

    return {
        "results": results,
        "errors": errors,
        "batches_processed": len(results) // batch_size,
    }

