            processed = dict(item)
            processed["processed_at"] = asyncio.get_event_loop().time()
            results.append(processed)
    while True:
        item = await _fetch_next()
        if item is None:
            if batch:
                await _process_batch(batch)
            break
        batch.append(item)
        if len(batch) >= batch_size:
            await _process_batch(batch)
            batch.clear()
    return {
        "processed_count": len(results),
        "errors": errors,
        "results": results,
