def analyze_records(
    records: List[Dict[str, Any]],
    key: str,
    threshold: float,
) -> Tuple[Dict[str, List[Dict[str, Any]]], Dict[str, int], Dict[str, Optional[float]]]:
    groups: Dict[str, List[Dict[str, Any]]] = {}
    counts: Dict[str, int] = {}

    for rec in records:
        if not isinstance(rec, dict):
            continue
        val = rec.get(key)
        if val is None:
            continue
        try:
            num = float(val)
        except (TypeError, ValueError):
            continue

        group = "above" if num >= threshold else "below"
        groups.setdefault(group, []).append(rec)
        counts[group] = counts.get(group, 0) + 1

    def _avg(group: str) -> Optional[float]:
        items = groups.get(group, [])
        if not items:
            return None
        total = sum(float(item[key]) for item in items if isinstance(item.get(key), (int, float, str)) and item.get(key) is not None)
        return total / len(items)

    averages: Dict[str, Optional[float]] = {g: _avg(g) for g in groups}

    return groups, counts, averages

