from typing import Any, Dict, AsyncIterator, List, Optional
async def process_data(
    stream: AsyncIterator[bytes],
    timeout: float = 5.0,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    total_bytes: int = 0
    start_time = asyncio.get_event_loop().time()
    async def _read_chunk() -> Optional[bytes]:
        try:
            data = await asyncio.wait_for(stream.__anext__(), timeout=timeout)
            return data
        except StopAsyncIteration:
            return None
        except asyncio.TimeoutError:
            errors.append("read timeout")
            return None
        except Exception as e:
            errors.append(str(e))
            return None
    while True:
        chunk = await _read_chunk()
        if chunk is None:
            break
        total_bytes += len(chunk)
        try:
            decoded = chunk.decode("utf-8")
            parts = decoded.splitlines()
            for part in parts:
                if part.strip():
                    results.append({"line": part.strip(), "bytes": len(part)})
        except UnicodeDecodeError as e:
            errors.append(f"decode error: {e}")
    return {
        "lines": results,
        "total_bytes": total_bytes,
        "errors": errors,
        "duration": asyncio.get_event_loop().time() - start_time,
    }

