def analyze_records(records: Iterable[Dict[str, Any]],
                      threshold: float = 0.0,
                      group_by: Optional[str] = None,
                      sort_key: Optional[str] = None) -> Tuple[Dict[str, List[Dict[str, Any]]], int]:
    def _is_valid(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        try:
            val = float(rec.get("score", 0))
            return val >= threshold
        except (TypeError, ValueError):
            return False
    def _normalize(rec: Dict[str, Any]) -> Dict[str, Any]:
        new_rec = dict(rec)
        try:
            new_rec["score"] = float(rec.get("score", 0))
        except (TypeError, ValueError):
            new_rec["score"] = 0.0
        return new_rec
    def _group(records: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for r in records:
            key = r.get(group_by, "__none__") if group_by else "__all__"
            groups.setdefault(key, []).append(r)
        return groups
    def _sort(group: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        if sort_key:
            return sorted(group, key=lambda x: x.get(sort_key, 0))
        return group
    valid = [r for r in records if _is_valid(r)]
    normalized = [_normalize(r) for r in valid]
    grouped = _group(normalized)
    for k in grouped:
        grouped[k] = _sort(grouped[k])
    total = sum(len(v) for v in grouped.values())
    return grouped, total

