async def fetch_and_process(
    urls: List[str],
    timeout: float = 5.0,
    max_concurrent: int = 5,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    semaphore = asyncio.Semaphore(max_concurrent)
    results: List[Dict[str, Any]] = []
    status_counts: Dict[str, int] = {}

    async def _fetch(url: str) -> Optional[Dict[str, Any]]:
        try:
            async with semaphore:
                async with asyncio.wait_for(
                    asyncio.open_connection(url.split("://")[1].split("/")[0], 80),
                    timeout=timeout,
                ) as (reader, writer):
                    request = f"GET / HTTP/1.1\\r\\nHost: {url.split('://')[1].split('/')[0]}\\r\\nConnection: close\\r\\n\\r\\n"
                    writer.write(request.encode())
                    await writer.drain()
                    data = await reader.read()
                    writer.close()
                    await writer.wait_closed()
                    return {"url": url, "status": "ok", "size": len(data)}
        except asyncio.TimeoutError:
            return {"url": url, "status": "timeout", "size": 0}
        except Exception as e:
            return {"url": url, "status": f"error:{e}", "size": 0}

    async def _process():
        tasks = [asyncio.create_task(_fetch(u)) for u in urls]
        for t in asyncio.as_completed(tasks):
            res = await t
            if res:
                results.append(res)
                status_counts[res["status"]] = status_counts.get(res["status"], 0) + 1

    await _process()

    def _filter_ok(res_list: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return [r for r in res_list if r.get("status") == "ok"]

    ok_results = _filter_ok(results)

    return ok_results, status_counts

