                results.append(item)
        except Exception as e:
            errors.append(str(e))
            retries += 1
            if retries > max_retries:
                break
            await asyncio.sleep(2 ** retries)
    return {
        "processed": len(results),
        "errors": errors,
        "data": results,
    }

