def weighted_average(values: List[float], weights: Optional[List[float]] = None) -> Tuple[float, float]:
    if not values:
        raise ValueError("values list cannot be empty")
    if weights is None:
        weights = [1.0] * len(values)
    if len(values) != len(weights):
        raise ValueError("values and weights must have same length")
    def _sum_product(vals: List[float], wts: List[float]) -> Tuple[float, float]:
        total_weight = 0.0
        weighted_sum = 0.0
        for v, w in zip(vals, wts):
            weighted_sum += v * w
            total_weight += w
        return weighted_sum, total_weight
    weighted_sum, total_weight = _sum_product(values, weights)
    average = weighted_sum / total_weight if total_weight != 0 else 0.0
    return average, total_weight

