    # Sort counts by descending frequency, then alphabetically
    sorted_counts = dict(sorted(counts.items(), key=lambda kv: (-kv[1], kv[0])))

    # Return top 10 most frequent keys
    top_keys = list(sorted_counts.keys())[:10]

    # Filter records to only include those with top keys
    final_records = [rec for rec in filtered if rec[key] in top_keys]

