async def process_stream(
    source: AsyncIterator[Dict[str, Any]],
    batch_size: int,
    timeout: float = 2.0,
) -> Dict[str, Any]:
    def _is_valid(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict): return False
        if 'id' not in record or 'value' not in record: return False
        if not isinstance(record['id'], int): return False
        if not isinstance(record['value'], (int, float)): return False
        return True

    def _summary() -> Dict[str, int]:
        return {"total_records": sum(len(b) for b in batches), "invalid_records": len(errors)}

    batches: List[List[Dict[str, Any]]] = []
    current: List[Dict[str, Any]] = []
    errors: List[str] = []

    async def _consume() -> None:
        try:
            async for item in source:
                if _is_valid(item):
                    current.append(item)
                    if len(current) >= batch_size:
                        batches.append(current)
                        current = []
                else:
                    errors.append(f"Invalid record: {item}")
        except asyncio.TimeoutError:
            errors.append("Timeout while consuming")
        except Exception as exc:
            errors.append(f"Unexpected error: {exc}")

    await asyncio.wait_for(_consume(), timeout=timeout)

    if current:
        batches.append(current)

    return {"batches": batches, "batch_count": len(batches), "errors": errors, "error_count": len(errors), **_summary()}

