 def process_records(
     records: Iterable[Dict[str, Any]],
     key: str,
     threshold: float,
     *,
     include_meta: bool = False,
     default_meta: Optional[Dict[str, Any]] = None,
 ) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
     def _is_valid(rec: Dict[str, Any]) -> bool:
         if not isinstance(rec, dict):
             return False
         if key not in rec:
             return False
         try:
             return float(rec[key]) >= threshold
         except (TypeError, ValueError):
             return False

     def _extract_meta(rec: Dict[str, Any]) -> Dict[str, Any]:
         meta = {}
         for k, v in rec.items():
             if k.startswith("meta_"):
                 meta[k[5:]] = v
         return meta

     valid_records: List[Dict[str, Any]] = []
     meta_counts: Dict[str, int] = {}

     for rec in records:
         if not _is_valid(rec):
             continue
         if include_meta:
             meta = _extract_meta(rec)
             merged = {**rec, **meta}
         else:
             merged = dict(rec)
         valid_records.append(merged)
         meta_counts.update({mk: meta_counts.get(mk, 0) + 1 for mk in merged})

     if default_meta is not None:
         for rec in valid_records:
             rec.update(default_meta)

     return valid_records, meta_counts

