            tags = [t.strip() for t in tags.split(",") if t.strip()]
        elif not isinstance(tags, Iterable):
            tags = []
        new_rec["tags"] = tags
        return new_rec
    def _filter_by_category(rec: Dict[str, Any], allowed: Optional[List[str]]) -> bool:
