async def process_stream(
    data_stream: AsyncIterator[Dict[str, Any]],
    batch_size: int,
    max_retries: int = 3,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    attempt: int = 0

    async def _fetch_batch() -> List[Dict[str, Any]]:  # inner async
        batch: List[Dict[str, Any]] = []
        try:
            async for item in data_stream:
                batch.append(item)
                if len(batch) >= batch_size:
                    break
        except Exception as e:
            raise e
        return batch

    async def _process_batch(batch: List[Dict[str, Any]]) -> None:
        for record in batch:
            # simulate processing
            if record.get("value") is None:
                raise ValueError("Missing value")
            results.append(record)

    while attempt < max_retries:
        try:
            batch = await asyncio.wait_for(_fetch_batch(), timeout=timeout)
            if not batch:
                break
            await _process_batch(batch)
            attempt = 0
        except (asyncio.TimeoutError, ValueError) as e:
            errors.append(str(e))
            attempt += 1
            if attempt >= max_retries:
                break
        except Exception as e:
            errors.append(f"Unexpected: {e}")
            break

    return {
        "processed": results,
        "errors": errors,
    }

