    def _filter_and_group(values: List[int]) -> Tuple[List[int], List[int]]:
        below = [v for v in values if v < threshold]
        above = [v for v in values if v >= threshold]
        return below, above

    if not nums:
        return {"below": (0, []), "above": (0, [])}

    below, above = _filter_and_group(nums)

    def _stats(lst: List[int]) -> Tuple[int, int]:
        return (min(lst) if lst else 0, max(lst) if lst else 0)
    result: Dict[str, Tuple[int, List[int]]] = {}
    result["below"] = (len(below), below)
    result["above"] = (len(above), above)
    result["below_stats"] = _stats(below)
    result["above_stats"] = _stats(above)
    return result

