def process_records(records: List[Dict[str, Any]], key: str, threshold: float, max_results: Optional[int] = None) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    def _parse_value(val: Any) -> float:
        try:
            return float(val)
        except (TypeError, ValueError):
            return 0.0

    def _filter(record: Dict[str, Any]) -> bool:
        if key not in record:
            return False
        return _parse_value(record[key]) >= threshold

    def _group(records: Iterable[Dict[str, Any]]) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for r in records:
            tag = r.get("tag", "unknown")
            counts[tag] = counts.get(tag, 0) + 1
        return counts

    def _sort(records: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return sorted(records, key=lambda x: _parse_value(x.get(key, 0)), reverse=True)

    if not isinstance(records, list):
        raise ValueError("records must be a list")

    filtered = [dict(r) for r in records if _filter(r)]

    if max_results is not None:
        filtered = filtered[:max_results]

    sorted_records = _sort(filtered)

    counts = _group(sorted_records)

    result: Tuple[List[Dict[str, Any]], Dict[str, int]] = (sorted_records, counts)

    return result

