    if not urls:
        return results
    async def _fetch(url: str) -> Optional[Any]:
        try:
            await asyncio.sleep(0.1)
            if "fail" in url:
                raise ValueError
            return {"url": url, "data": f"content_of_{url}"}
        except Exception:
            return None
    tasks = [asyncio.create_task(_fetch(u)) for u in urls]
    done, pending = await asyncio.wait(tasks, timeout=timeout)
    for t in done:
