def weighted_average(values: List[float], weights: Optional[List[float]] = None) -> Dict[str, float]:
    def _validate(vals: List[float]) -> bool:
        return all(isinstance(v, (int, float)) for v in vals)
    if not _validate(values):
        raise ValueError("values must be numeric")
    if weights is not None:
        if not _validate(weights):
            raise ValueError("weights must be numeric")
        if len(values) != len(weights):
            raise ValueError("values and weights must be same length")
    if weights:
        total = sum(v * w for v, w in zip(values, weights)); denom = sum(weights)
    else:
        total = sum(values); denom = len(values)
    avg = total / denom if denom else 0.0
    return {"average": avg, "count": len(values)}

