from typing import List, Dict, Tuple, Optional

def compute_stats(values: List[float]) -> Dict[str, Optional[float]]:
    def _mean(vs: List[float]) -> Optional[float]:
        return sum(vs) / len(vs) if vs else None

    def _median(vs: List[float]) -> Optional[float]:
        if not vs:
            return None
        sorted_vs = sorted(vs)
        mid = len(sorted_vs) // 2
        if len(sorted_vs) % 2 == 0:
            return (sorted_vs[mid - 1] + sorted_vs[mid]) / 2
        return sorted_vs[mid]

    def _std(vs: List[float]) -> Optional[float]:
        m = _mean(vs)
        if m is None:
            return None
        variance = sum((x - m) ** 2 for x in vs) / len(vs)
        return variance ** 0.5

    return {
        "mean": _mean(values),
        "median": _median(values),
        "std_dev": _std(values)
    }

