from typing import Dict, List, Tuple, Optional, Any

def analyze_text(lines: List[str], min_word_len: int = 3) -> Dict[str, Any]:
    # Inner helper to split a line into words
    def _split(line: str) -> List[str]:
        return re.findall(r"[A-Za-z']+", line.lower())

    # Inner helper to filter words by length
    def _filter(words: List[str]) -> List[str]:
        return [w for w in words if len(w) >= min_word_len]

    word_counts: Dict[str, int] = {}
    total_words = 0
    unique_words = 0

    for line in lines:
        words = _split(line)
        words = _filter(words)
        total_words += len(words)
        for w in words:
            if w in word_counts:
                word_counts[w] += 1
            else:
                word_counts[w] = 1

    unique_words = len(word_counts)

    # Sort words by frequency descending
    sorted_words = sorted(word_counts.items(), key=lambda kv: kv[1], reverse=True)

    # Build result
    result: Dict[str, Any] = {
        "total_words": total_words,
        "unique_words": unique_words,
        "top_words": sorted_words[:10],
    }
    return result

