import datetime

def process_records(records: List[Dict[str, Any]], *, min_date: Optional[datetime.date] = None, pattern: Optional[str] = None) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    def _parse_date(val: Any) -> Optional[datetime.date]:
        if isinstance(val, datetime.date):
            return val
        if isinstance(val, str):
            try:
                return datetime.datetime.strptime(val, "%Y-%m-%d").date()
            except ValueError:
                return None
        return None
    def _match_pattern(text: str) -> bool:
        if pattern is None:
            return True
        return re.search(pattern, text) is not None
    filtered: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    for rec in records:
        if not isinstance(rec, dict):
            continue
        date_val = rec.get("date")
        parsed_date = _parse_date(date_val)
        if min_date is not None and (parsed_date is None or parsed_date < min_date):
            continue
        text = rec.get("text", "")
        if not isinstance(text, str):
            text = ""
        if not _match_pattern(text):
            continue
        key = rec.get("category", "unknown")
        if not isinstance(key, str):
            key = "unknown"
        counts[key] = counts.get(key, 0) + 1
        new_rec = dict(rec)
        new_rec["parsed_date"] = parsed_date
        filtered.append(new_rec)
    sorted_counts = dict(sorted(counts.items(), key=lambda kv: (-kv[1], kv[0])))
    return filtered, sorted_counts

