def compute_stats(values: Iterable[int]) -> Tuple[float, float, int]:
    data = list(values)
    if not data:
        return (0.0, 0.0, 0)
    total = sum(data)
    count = len(data)
    avg = total / count
    def _median(lst: List[int]) -> float:
        sorted_lst = sorted(lst)
        mid = count // 2
        if count % 2 == 0:
            return (sorted_lst[mid - 1] + sorted_lst[mid]) / 2.0
        else:
            return float(sorted_lst[mid])
    med = _median(data)
    return (avg, med, count)

