def process_records(records: List[Dict[str, Any]], *, threshold: float = 0.0, group_by: str = "category") -> Tuple[Dict[str, List[Dict[str, Any]]], Dict[str, int]]:
    def _validate(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        if group_by not in record:
            return False
        try:
            val = float(record.get("value", 0))
        except (TypeError, ValueError):
            return False
        return val >= threshold

    def _normalize(record: Dict[str, Any]) -> Dict[str, Any]:
        new = dict(record)
        # normalize date field if present
        if "date" in new:
            try:
                new["date"] = datetime.datetime.fromisoformat(new["date"])
            except Exception:
                new["date"] = None
        return new

    groups: Dict[str, List[Dict[str, Any]]] = {}
    counts: Dict[str, int] = {}

    for rec in records:
        if not _validate(rec):
            continue
        norm_rec = _normalize(rec)
        key = norm_rec.get(group_by, "unknown")
        groups.setdefault(key, []).append(norm_rec)
        counts[key] = counts.get(key, 0) + 1

    # sort groups by count descending
    sorted_keys = sorted(counts.keys(), key=lambda k: (-counts[k], k))
    sorted_groups = {k: groups[k] for k in sorted_keys}

    return sorted_groups, counts

