        if "value" not in record:
            return False
        try:
            float(record["value"])
        except (TypeError, ValueError):
            return False
        return True

    def _normalize(record: Dict[str, Any]) -> Dict[str, Any]:
        new_rec = dict(record)
        val = new_rec.get("value")
        if isinstance(val, (int, float)):
