        else:
            new_rec["value"] = 0.0
        return new_rec

    high: List[Dict[str, Any]] = []
    low: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {"high": 0, "low": 0}

    for rec in records:
        if not _validate(rec):
