        norm_rec = _normalize(rec)
        if norm_rec["value"] >= threshold:
            high.append(norm_rec)
            counts["high"] += 1
        else:
            low.append(norm_rec)
            counts["low"] += 1

    # Sort high by descending value, low by ascending
    high.sort(key=lambda r: r["value"], reverse=True)
    low.sort(key=lambda r: r["value"])

    return high, low, counts

