def process_data(records: List[Dict[str, Any]], threshold: float, max_records: Optional[int] = None) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    def _validate(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        if "value" not in record:
            return False
        try:
            val = float(record["value"])
        except (TypeError, ValueError):
            return False
        return val >= threshold

    def _aggregate(valid_records: List[Dict[str, Any]]) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for rec in valid_records:
            key = rec.get("category", "unknown")
            counts[key] = counts.get(key, 0) + 1
        return counts

    def _limit(records_list: List[Dict[str, Any]], limit: Optional[int]) -> List[Dict[str, Any]]:
        if limit is None or limit <= 0:
            return records_list
        return records_list[:limit]

    def _sort_by_value(records_list: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return sorted(records_list, key=lambda r: float(r.get("value", 0)), reverse=True)

    def _format_counts(counts_dict: Dict[str, int]) -> str:
        items = sorted(counts_dict.items(), key=lambda kv: (-kv[1], kv[0]))
        return ", ".join(f"{k}:{v}" for k, v in items)

    valid: List[Dict[str, Any]] = []
    for rec in records:
        if _validate(rec):
            valid.append(dict(rec))

    valid = _limit(valid, max_records)
    valid = _sort_by_value(valid)
    counts = _aggregate(valid)
    return valid, counts

