async def fetch_and_process(
    source: AsyncIterator[Dict[str, Any]],
    limit: int,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    async def _process(item: Dict[str, Any]) -> None:
        try:
            val = int(item.get("value", 0))
            item["value"] = val * 2
            results.append(item)
        except Exception as e:
            errors.append(str(e))

    try:
        async for idx, item in enumerate(source):
            if idx >= limit:
                break
            await _process(item)
    except asyncio.TimeoutError: errors.append("timeout")

    return {"processed": results, "errors": errors, "count": len(results)}

from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_records(
    records: List[Dict[str, Any]],
    key: str,
    threshold: float,
    *,
    include_missing: bool = False,
    transform: Optional[callable] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    filtered: List[Dict[str, Any]] = []
    stats: Dict[str, int] = {}
    def _get_value(rec: Dict[str, Any]) -> Optional[float]:
        val = rec.get(key)
        if isinstance(val, (int, float)):
            return float(val)
        try:
            return float(val)
        except (TypeError, ValueError):
            return None
    for rec in records:
        val = _get_value(rec)
        if val is None:
            if include_missing:
                filtered.append(rec)
            continue
        if val >= threshold:
            if transform:
                rec = transform(rec)
            filtered.append(rec)
            stats[key] = stats.get(key, 0) + 1

    return filtered, stats

from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_records(
    records: List[Dict[str, Any]],
    key: str,
    threshold: float,
    *,
    include_meta: bool = False,
    default_meta: Optional[str] = None,
) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]], Dict[str, int]]:
    def _validate(r: Dict[str, Any]) -> bool:
        if not isinstance(r, dict):
            return False
        if key not in r:
            return False
        try:
            val = float(r[key])
        except (TypeError, ValueError):
            return False
        return val >= threshold
    def _extract_meta(r: Dict[str, Any]) -> Optional[str]:
        meta = r.get("meta")
        if meta is None:
            return default_meta
        return str(meta).strip()
    high: List[Dict[str, Any]] = []
    low: List[Dict[str, Any]] = []
    meta_counts: Dict[str, int] = {}
    for rec in records:
        if not isinstance(rec, dict):
            continue
        if _validate(rec):
            high.append(rec.copy())
        else:
            low.append(rec.copy())
        if include_meta:
            m = _extract_meta(rec)
            if m:
                meta_counts[m] = meta_counts.get(m, 0) + 1
    return high, low, meta_counts

