    counts: Dict[str, int] = {}
    def _extract_value(item: Dict[str, Any]) -> Optional[float]:
        try:
            return float(item.get(key, 0))
        except (TypeError, ValueError):
            return None
    for item in items:
        val = _extract_value(item)
        if val is None or val < threshold:
            continue
        tag = str(item.get("tag", default or "")).strip().lower()
        counts[tag] = counts.get(tag, 0) + 1
        new_item = dict(item)
        new_item[key] = val
        filtered.append(new_item)

        # End of loop
    return filtered, counts

