from typing import Any, AsyncIterator, Dict, List, Optional, Tuple

async def process_stream(
    stream: AsyncIterator[Dict[str, Any]],
    max_items: int,
    timeout: float = 5.0,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    collected: List[Dict[str, Any]] = []
    summary: Dict[str, Any] = {"count": 0, "errors": 0}

    def _validate_item(item: Any) -> Optional[Dict[str, Any]]:
        if not isinstance(item, dict):
            return None
        if "id" not in item or "value" not in item:
            return None
        return {"id": item["id"], "value": item["value"]}

    async def _consume() -> None:
        nonlocal summary
        try:
            async for raw in stream:
                validated = _validate_item(raw)
                if validated is None:
                    summary["errors"] += 1
                    continue
                collected.append(validated)
                summary["count"] += 1
                if len(collected) >= max_items:
                    break
        except asyncio.TimeoutError:
            summary["errors"] += 1
            summary["timeout"] = True
        except Exception:
            summary["errors"] += 1

    try:
        await asyncio.wait_for(_consume(), timeout=timeout)
    except asyncio.TimeoutError:
        summary["errors"] += 1
        summary["timeout"] = True

    return collected, summary

from typing import Dict, List, Optional

def summarize_numbers(values: List[int], threshold: int = 10) -> Dict[str, Optional[int]]:
    if not values:
        return {"count": None, "sum": None, "max": None, "min": None}

    total = 0
    max_val = values[0]
    min_val = values[0]
    above = 0
    for v in values:
        total += v
        if v > max_val:
            max_val = v
        if v < min_val:
            min_val = v
        if v >= threshold:
            above += 1

    return {"count": len(values), "sum": total, "max": max_val, "min": min_val, "above_threshold": above}

