from typing import List, Dict, Any, Tuple, Optional

def process_records(records: List[Dict[str, Any]], min_score: float = 0.0) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    def _validate(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if 'score' not in rec:
            return False
        try:
            return float(rec['score']) >= min_score
        except (TypeError, ValueError):
            return False
    def _normalize(rec: Dict[str, Any]) -> Dict[str, Any]:
        new_rec = dict(rec)
        for k, v in rec.items():
            if isinstance(v, str):
                new_rec[k] = v.strip()
        return new_rec
    valid_records: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    for r in records:
        if _validate(r):
            norm = _normalize(r)
            valid_records.append(norm)
            key = norm.get('category', 'unknown')
            counts[key] = counts.get(key, 0) + 1
    def _average_score(recs: List[Dict[str, Any]]) -> Optional[float]:
        if not recs:
            return None
        total = 0.0
        for rec in recs:
            try:
                total += float(rec.get('score', 0))
            except (TypeError, ValueError):
                continue
        return total / len(recs)
    avg_score = _average_score(valid_records)
    summary: Dict[str, Any] = {
        'total_valid': len(valid_records),
        'average_score': avg_score,
        'categories': counts
    }
    return valid_records, summary

