from typing import Dict, List, Tuple, Optional

async def fetch_urls(urls: List[str], timeout: float = 5.0) -> Dict[str, Tuple[int, int]]:
    results: Dict[str, Tuple[int, int]] = {}
    errors: Dict[str, str] = {}

    async def _fetch(url: str) -> None:
        try:
            await asyncio.sleep(0.1)  # simulate network latency
            if "bad" in url:
                raise ValueError("bad url")
            status = 200
            content = f"Content of {url}"
            results[url] = (status, len(content))
        except Exception as e:
            errors[url] = str(e)

    tasks = [_fetch(u) for u in urls]
    try:
        await asyncio.wait_for(asyncio.gather(*tasks), timeout=timeout)
    except asyncio.TimeoutError:
        for u in urls:
            if u not in results and u not in errors:
                errors[u] = "timeout"

    return {**results, **{u: (-1, 0) for u in errors}}

