async def fetch_multiple(urls: List[str], timeout: float = 5.0) -> Dict[str, Any]:
    results: Dict[str, Any] = {}
    errors: Dict[str, str] = {}
    def _is_valid(url: str) -> bool:
        return url.startswith("http://") or url.startswith("https://")
    async def _fetch(url: str) -> None:
        try:
            async with asyncio.timeout(timeout):
                await asyncio.sleep(0.1)
                content = f"Content from {url}"
                results[url] = content
        except asyncio.TimeoutError:
            errors[url] = "timeout"
        except Exception as e:
            errors[url] = str(e)
    for u in urls:
        if not _is_valid(u):
            errors[u] = "invalid_url"
    valid_urls = [u for u in urls if _is_valid(u)]
    if not valid_urls:
        return {"results": {}, "errors": errors, "count": len(urls)}
    tasks = [_fetch(u) for u in valid_urls]
    await asyncio.gather(*tasks)
    return {
        "results": results,
        "errors": errors,
        "count": len(urls),
    }

