from typing import Any, Dict, Iterable, List, Optional, Tuple

async def filter_and_aggregate(
    items: Iterable[Dict[str, Any]],
    key: str,
    threshold: float,
    *,
    max_results: Optional[int] = None,
    timeout: float = 5.0,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    if not isinstance(items, Iterable): raise TypeError("items must be an iterable")
    if not isinstance(key, str): raise TypeError("key must be a string")
    if not isinstance(threshold, (int, float)): raise TypeError("threshold must be numeric")
    results: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    async def _match(item: Dict[str, Any]) -> bool:
        try:
            return float(item.get(key, 0)) >= threshold
        except (TypeError, ValueError):
            return False
    async def _worker() -> None:
        for item in items:
            if max_results is not None and len(results) >= max_results: break
            if await _match(item):
                results.append(dict(item))
                tag = str(item.get(key, "")).strip().lower()
                counts[tag] = counts.get(tag, 0) + 1
    try:
        await asyncio.wait_for(_worker(), timeout=timeout)
    except asyncio.TimeoutError:
        pass
    return results, counts

