def process_items(items: List[Dict[str, int]], threshold: int = 10) -> Dict[str, List[int]]:
    def _filter(item: Dict[str, int]) -> bool:
        return item.get("value", 0) > threshold

    filtered: List[Dict[str, int]] = [i for i in items if _filter(i)]
    result: Dict[str, List[int]] = {"ids": [], "values": []}
    for itm in filtered:
        result["ids"].append(itm.get("id", -1))
        result["values"].append(itm.get("value", 0))

    if not result["ids"]:
        result["ids"].append(-1)
        result["values"].append(0)

    return result

from typing import Any, Dict, Iterable, List, Optional, Tuple

def aggregate_by_category(
    items: List[Dict[str, Any]],
    category_key: str,
    value_key: str,
    min_value: Optional[float] = None,
) -> Dict[str, Any]:
    def _is_valid(item: Dict[str, Any]) -> bool:
        if not isinstance(item, dict):
            return False
        if category_key not in item or value_key not in item:
            return False
        try:
            val = float(item[value_key])
        except (TypeError, ValueError):
            return False
        if min_value is not None and val < min_value:
            return False
        return True
    aggregates: Dict[str, Dict[str, float]] = {}
    counts: Dict[str, int] = {}
    for itm in items:
        if not _is_valid(itm):
            continue
        cat = str(itm[category_key]).strip()
        val = float(itm[value_key])
        if cat not in aggregates:
            aggregates[cat] = {"sum": 0.0, "min": val, "max": val}
            counts[cat] = 0
        aggregates[cat]["sum"] += val
        aggregates[cat]["min"] = min(aggregates[cat]["min"], val)
        aggregates[cat]["max"] = max(aggregates[cat]["max"], val)
        counts[cat] += 1
    result: Dict[str, Any] = {}
    for cat, agg in aggregates.items():
        count = counts[cat]
        avg = agg["sum"] / count if count else 0.0
        result[cat] = {
            "count": count,
            "sum": agg["sum"],
            "min": agg["min"],
            "max": agg["max"],
            "average": avg,
        }
    return result

