from typing import Any, AsyncIterator, Dict, List, Optional, Tuple

async def process_stream(
    stream: AsyncIterator[Dict[str, Any]],
    max_items: int,
    filter_key: str = "active",
    filter_value: Any = True,
    timeout: float = 5.0,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    results: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {"count": 0, "errors": 0}
    err: Optional[str] = None

    async def _fetch() -> None:
        nonlocal err
        try:
            async for item in stream:
                if stats["count"] >= max_items:
                    break
                if item.get(filter_key) == filter_value:
                    results.append(item)
                    stats["count"] += 1
                else:
                    stats["errors"] += 1
        except asyncio.TimeoutError:
            err = "timeout"
        except Exception as e:
            err = str(e)

    try:
        await asyncio.wait_for(_fetch(), timeout=timeout)
    except asyncio.TimeoutError:
        err = err or "timeout"

    # Ensure results are sorted by a key if present
    if results and "timestamp" in results[0]:
        results.sort(key=lambda x: x.get("timestamp"))

    return results, {"count": stats["count"], "errors": stats["errors"], "error": err}

