import random
import string

def generate_passwords(
    count: int,
    length: int = 12,
    include_digits: bool = True,
    include_symbols: bool = False,
) -> List[str]:
    # Build character set
    chars = string.ascii_letters
    if include_digits:
        chars += string.digits
    if include_symbols:
        chars += string.punctuation

    def _random_pw() -> str:
        return ''.join(random.choice(chars) for _ in range(length))

    passwords: List[str] = []
    for _ in range(count):
        pw = _random_pw()
        # Ensure at least one digit if requested
        if include_digits and not any(c.isdigit() for c in pw):
            pw = _random_pw()
        # Ensure at least one symbol if requested
        if include_symbols and not any(c in string.punctuation for c in pw):
            pw = _random_pw()
        passwords.append(pw)
    return passwords

