        try:
            return int(rec.get("value", 0)) > threshold
        except (ValueError, TypeError):
            return False

    filtered: List[Dict[str, str]] = []
    count: int = 0
    for rec in records:
        if _valid(rec):
            filtered.append(rec.copy())
            count += 1
    total: int = 0
    for rec in filtered:
        try:
            total += int(rec.get("value", 0))
        except (ValueError, TypeError):
            continue

    average: Optional[float] = None
    if filtered:
        average = total / len(filtered)
    return filtered, count, average

