def filter_and_transform(records: List[Dict[str, Any]], threshold: float) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]]]:
    def _is_valid(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        if "value" not in record:
            return False
        try:
            val = float(record["value"])
        except (TypeError, ValueError):
            return False
        return val >= threshold

    def _transform(record: Dict[str, Any]) -> Dict[str, Any]:
        new_rec = dict(record)
        new_rec["value"] = float(new_rec["value"])
        new_rec["status"] = "high" if new_rec["value"] >= threshold else "low"
        return new_rec

    high: List[Dict[str, Any]] = []
    low: List[Dict[str, Any]] = []

    for rec in records:
        if not _is_valid(rec):
            continue
        transformed = _transform(rec)
        if transformed["value"] >= threshold:
            high.append(transformed)
        else:
            low.append(transformed)





    return high, low

