from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_data(
    items: List[Dict[str, Any]],
    threshold: float,
    *,
    key: str = "value",
    default: Optional[float] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    def _extract(item: Dict[str, Any]) -> float:
        try:
            return float(item.get(key, default))
        except (TypeError, ValueError):
            return default if default is not None else 0.0

    def _filter(items: Iterable[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return [i for i in items if _extract(i) >= threshold]
    def _count_by(items: Iterable[Dict[str, Any]]) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for i in items:
            k = i.get("category", "unknown")
            counts[k] = counts.get(k, 0) + 1
        return counts
    filtered = _filter(items)
    counts = _count_by(filtered)
    return filtered, counts

