def aggregate_stats(
    items: Iterable[Dict[str, Any]],
    key: str,
    threshold: Optional[float] = None,
) -> Tuple[Dict[str, int], List[Dict[str, Any]]]:
    def _valid(item: Dict[str, Any]) -> bool:
        if not isinstance(item, dict):
            return False
        if key not in item:
            return False
        try:
            val = float(item[key])
        except (TypeError, ValueError):
            return False
        if threshold is not None and val < threshold:
            return False
        return True

    counts: Dict[str, int] = {}
    filtered: List[Dict[str, Any]] = []

    for itm in items:
        if _valid(itm):
            k = str(itm[key]).strip().lower()
            counts[k] = counts.get(k, 0) + 1
            filtered.append(dict(itm))

    # Sort counts by descending frequency, then alphabetically
    sorted_counts = dict(sorted(counts.items(), key=lambda kv: (-kv[1], kv[0])))

    # Compute summary of total items processed
    total_processed = len(filtered)
    # Compute average value if threshold is set
    if threshold is not None:
        avg_val = sum(float(itm[key]) for itm in filtered) / total_processed if total_processed else 0.0
    else:
        avg_val = None
    sorted_counts["__summary__"] = f"total:{total_processed}, avg:{avg_val}"

    return sorted_counts, filtered

