 def process_records(
     records: List[Dict[str, Any]],
     key: str,
     threshold: float,
     *,
     include_meta: bool = False,
     meta_key: str = 'meta',
 ) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
     # Filter records based on threshold and optionally include normalized metadata
     filtered: List[Dict[str, Any]] = []
     counts: Dict[str, int] = {}

     def _extract_value(rec: Dict[str, Any]) -> Optional[float]:
         val = rec.get(key)
         try:
             return float(val)
         except (TypeError, ValueError):
             return None

     def _normalize_meta(rec: Dict[str, Any]) -> Dict[str, Any]:
         meta = rec.get(meta_key, {})
         if isinstance(meta, dict):
             return {k.lower(): v for k, v in meta.items()}
         return {}

     for rec in records:
         if not isinstance(rec, dict):
             continue
         val = _extract_value(rec)
         if val is None or val < threshold:
             continue
         new_rec = dict(rec)
         new_rec[key] = val
         if include_meta:
             new_rec.update(_normalize_meta(rec))
         filtered.append(new_rec)
         counts[key] = counts.get(key, 0) + 1

     # Sort filtered by key descending
     filtered.sort(key=lambda r: r[key], reverse=True)

     def _summary() -> str:
         return f'Processed {len(filtered)} records with {counts.get(key,0)} matches.'

     # Optionally, you could log the summary here
