async def process_stream(stream: AsyncIterator[Dict[str, Any]], batch_size: int, max_retries: int = 3) -> Dict[str, Any]:
    batches: List[List[Dict[str, Any]]] = []
    current_batch: List[Dict[str, Any]] = []
    errors: List[str] = []

    def _validate(rec: Dict[str, Any]) -> bool:
        return 'id' in rec and 'value' in rec and isinstance(rec['id'], int) and isinstance(rec['value'], (int, float))

    def _transform(rec: Dict[str, Any]) -> Dict[str, Any]:
        r = dict(rec)
        r['normalized'] = float(rec['value']) / 100.0
        return r

    async def _retry_fetch() -> Optional[Dict[str, Any]]:
        for attempt in range(max_retries):
            try:
                await asyncio.sleep(0.1)
                return {'id': attempt, 'value': attempt * 10}
            except Exception as e:
                errors.append(f"retry {attempt}: {e}")
                await asyncio.sleep(0.2 * (attempt + 1))
        return None

    async def _process_batch(batch: List[Dict[str, Any]]) -> None:
        for rec in batch:
            if _validate(rec):
                _transform(rec)  # placeholder for downstream

    async for rec in stream:
        if _validate(rec):
            current_batch.append(_transform(rec))
            if len(current_batch) >= batch_size:
                await _process_batch(current_batch)
                batches.append(current_batch)
                current_batch = []
        else:
            errors.append(f"invalid: {rec}")

    if current_batch:
        await _process_batch(current_batch)
        batches.append(current_batch)

    return {'batches': len(batches), 'records': sum(len(b) for b in batches), 'errors': errors}

