def process_data(
    data: Iterable[Dict[str, Any]],
    key: str,
    threshold: float,
) -> Dict[str, Any]:
    # Validate input
    if not isinstance(data, Iterable):
        return {"error": "data must be iterable"}

    def _extract_value(item: Dict[str, Any]) -> Optional[float]:
        try:
            val = float(item.get(key, None))
            return val
        except (TypeError, ValueError):
            return None

    high: List[Dict[str, Any]] = []
    low: List[Dict[str, Any]] = []
    stats: Dict[str, float] = {"count": 0.0, "sum": 0.0, "max": float("-inf"), "min": float("inf")}

    for entry in data:
        if not isinstance(entry, dict):
            continue
        val = _extract_value(entry)
        if val is None:
            continue
        stats["count"] += 1
        stats["sum"] += val
        if val > stats["max"]:
            stats["max"] = val
        if val < stats["min"]:
            stats["min"] = val
        if val >= threshold:
            high.append(entry)
        else:
            low.append(entry)

    if stats["count"] > 0:
        stats["average"] = stats["sum"] / stats["count"]
    else:
        stats["average"] = None

    return {"high": high, "low": low, "stats": stats}

