async def process_items(
    items: List[Dict[str, Any]],
    threshold: float,
    max_retries: int = 3,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    def _normalize(item: Dict[str, Any]) -> Dict[str, Any]:
        val = item.get("value")
        item["value"] = float(val) if isinstance(val, (int, float)) else 0.0
        return item

    async def _worker(it: Dict[str, Any], retries: int) -> Optional[Dict[str, Any]]:
        try:
            await asyncio.sleep(0.01)
            if it["value"] < threshold: return None
            return _normalize(it)
        except Exception:
            if retries > 0: return await _worker(it, retries - 1)
            return None

    results: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}

    for itm in items:
        processed = await _worker(itm, max_retries)
        if processed:
            results.append(processed)
            key = processed.get("category", "unknown")
            counts[key] = counts.get(key, 0) + 1

    return results, counts

