        if val >= threshold:
            counts[norm] = counts.get(norm, 0) + 1
            valid_items.append(dict(item))

    sorted_counts = dict(sorted(counts.items(), key=lambda kv: (-kv[1], kv[0])))
    return valid_items, sorted_counts

