    counts: dict[str, int] = {}
    def _normalize(word: str) -> str:
        return word.strip().lower()
    async def _process_line(line: str) -> None:
        if len(line) < min_len:
            return
        for w in line.split():
            w_norm = _normalize(w)
            if not w_norm:
                continue
            if len(w_norm) > max_words:
                continue
            counts[w_norm] = counts.get(w_norm, 0) + 1
    # accumulate word frequencies
    # skip words longer than max_words
    try:
        async for line in stream:
            await _process_line(line)
    except Exception:
        pass
    return counts

