async def process_data(
    stream: AsyncIterator[Dict[str, Any]],
    batch_size: int,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    import asyncio
    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    batch: List[Dict[str, Any]] = []
    async def _fetch_next() -> Optional[Dict[str, Any]]:
        try:
            return await stream.__anext__()
        except StopAsyncIteration:
            return None
        except Exception as e:
            errors.append(str(e))
            return None
    async def _process_batch(b: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = 0
        count = 0
        for item in b:
            val = item.get("value")
            if isinstance(val, (int, float)):
                total += val
                count += 1
        return {"batch_sum": total, "batch_count": count}
    try:
        while True:
            item = await asyncio.wait_for(_fetch_next(), timeout=timeout)
            if item is None:
                break
            batch.append(item)
            if len(batch) >= batch_size:
                res = await _process_batch(batch)
                results.append(res)
                batch.clear()
    except asyncio.TimeoutError:
        errors.append("timeout reached while fetching")
    except Exception as e:
        errors.append(f"unexpected error: {e}")
    if batch:
        res = await _process_batch(batch)
        results.append(res)




    return {"results": results, "errors": errors}

