async def stream_processor(source: AsyncIterator[Dict[str, Any]], key: str, max_items: int = 100, timeout: float = 5.0) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    results: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    err: Optional[str] = None

    async def _collect() -> None:
        nonlocal err
        try:
            async for item in source:
                if not isinstance(item, dict):
                    continue
                val = item.get(key)
                if val is None:
                    continue
                key_str = str(val).strip()
                counts[key_str] = counts.get(key_str, 0) + 1
                results.append(item)
                if len(results) >= max_items:
                    break
        except asyncio.TimeoutError:
            err = "timeout reached during collection"
        except Exception as e:
            err = str(e)

    try:
        await asyncio.wait_for(_collect(), timeout=timeout)
    except asyncio.TimeoutError:
        err = err or "overall timeout"

    return results, counts

