def process_records(records: Iterable[Dict[str, Any]], threshold: float) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    def _validate(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        if "value" not in record:
            return False
        try:
            return float(record["value"]) >= threshold
        except (TypeError, ValueError):
            return False
    def _normalize(record: Dict[str, Any]) -> Dict[str, Any]:
        new_rec = dict(record)
        if "name" in new_rec:
            new_rec["name"] = str(new_rec["name"]).strip().title()
        return new_rec
    valid_records: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    for rec in records:
        if not _validate(rec):
            continue
        norm_rec = _normalize(rec)
        valid_records.append(norm_rec)
        key = norm_rec.get("category", "unknown")
        counts[key] = counts.get(key, 0) + 1
    # Sort valid_records by value descending
    valid_records.sort(key=lambda r: float(r["value"]), reverse=True)
    # Prepare summary
    summary = {k: v for k, v in counts.items()}
    # Compute averages
    def _compute_averages(records: List[Dict[str, Any]]) -> Dict[str, float]:
        totals: Dict[str, float] = {}
        counts_local: Dict[str, int] = {}
        for r in records:
            cat = r.get("category", "unknown")
            val = float(r["value"])
            totals[cat] = totals.get(cat, 0.0) + val
            counts_local[cat] = counts_local.get(cat, 0) + 1
        averages: Dict[str, float] = {}
        for cat, total in totals.items():
            averages[cat] = total / counts_local[cat]
        return averages
    averages = _compute_averages(valid_records)
    for cat, avg in averages.items():
        summary[cat + "_avg"] = avg
    # Final output includes sorted records and summary with averages
    # End of processing
    # Return the processed data
    return valid_records, summary

