    key: str,
    threshold: float,
    *,
    include_missing: bool = False,
    max_items: Optional[int] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    def _extract_value(rec: Dict[str, Any]) -> Optional[float]:
        val = rec.get(key)
        if val is None:
            return None
        try:
            return float(val)
        except (TypeError, ValueError):
            return None

    def _normalize(rec: Dict[str, Any]) -> Dict[str, Any]:
        new_rec = dict(rec)
        val = _extract_value(rec)
        if val is not None:
            new_rec[key] = val
        else:
            new_rec[key] = None
        return new_rec

    filtered: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}

    for rec in records:
        norm_rec = _normalize(rec)
        val = norm_rec.get(key)
        if val is None:
            if include_missing:
                filtered.append(norm_rec)
                counts["missing"] = counts.get("missing", 0) + 1
            continue
        if val >= threshold:
            filtered.append(norm_rec)
            counts["above"] = counts.get("above", 0) + 1
        else:
            counts["below"] = counts.get("below", 0) + 1

    if max_items is not None:
        filtered = filtered[:max_items]

    return filtered, counts

