async def fetch_and_aggregate(urls: List[str], timeout: float = 5.0) -> Tuple[List[Dict[str, Any]], Optional[str]]:
    results: List[Dict[str, Any]] = []
    error: Optional[str] = None

    async def _fetch(url: str) -> Optional[Dict[str, Any]]:
        try:
            host = url.split("://")[1]
            reader, writer = await asyncio.wait_for(asyncio.open_connection(host, 80), timeout=timeout)
            request = f"GET / HTTP/1.1\r\nHost: {host}\r\nConnection: close\r\n\r\n"
            writer.write(request.encode())
            await writer.drain()
            data = await reader.read()
            writer.close()
            await writer.wait_closed()
            try:
                return {"url": url, "content": data.decode()}
            except UnicodeDecodeError:
                return {"url": url, "content": "<binary data>"}
        except Exception as e:
            return None

    tasks = [asyncio.create_task(_fetch(u)) for u in urls]
    try:
        fetched = await asyncio.gather(*tasks, return_exceptions=False)
    except Exception as e:
        error = str(e)
        fetched = []

    for item in fetched:
        if item is not None:
            results.append(item)

    return results, error

