async def aggregate_async_stream(
    stream: AsyncIterator[Dict[str, Any]],
    key: str,
    limit: int,
    *,
    timeout: float = 5.0,
) -> Dict[str, Any]:
    def _process(item: Dict[str, Any]) -> Tuple[Any, int]:
        value = item.get(key)
        if value is None:
            return None, 0
        try:
            numeric = float(value)
        except (TypeError, ValueError):
            return None, 0
        return numeric, 1

    results: List[Dict[str, Any]] = []
    counts: Dict[Any, int] = {}
    total_processed = 0

    async def _consume() -> None:
        nonlocal total_processed
        async for item in stream:
            val, inc = _process(item)
            if val is not None:
                results.append(item)
                counts[val] = counts.get(val, 0) + inc
                total_processed += inc
            if total_processed >= limit:
                break

    try:
        await asyncio.wait_for(_consume(), timeout=timeout)
    except asyncio.TimeoutError:
        return {"status": "timeout", "processed": total_processed, "results": results, "counts": counts}
    except Exception as e:
        return {"status": "error", "message": str(e), "processed": total_processed, "results": results, "counts": counts}
    return {"status": "ok", "processed": total_processed, "results": results, "counts": counts}

