            if rec_value < min_val:
                min_val = rec_value
        avg = total / count if count else 0.0
        return {
            "total": total,
            "count": count,
            "average": avg,
            "max": max_val,
            "min": min_val,
        }
    valid_records = [r for r in records if _validate(r)]
    transformed = [_transform(r) for r in valid_records]
    stats = _aggregate(transformed)
    return {
        "stats": stats,
        "valid_count": len(valid_records),
        "invalid_count": len(records) - len(valid_records),
    }

