        return new_item

    async def _worker(item: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        retries = 0
        while retries < max_retries:
            try:
                await asyncio.sleep(0); return _validate(item)
            except Exception:
                retries += 1; await asyncio.sleep(0.1)
        return None

    processed: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    tasks = [asyncio.create_task(_worker(it)) for it in items]
    for task in asyncio.as_completed(tasks):
        result = await task
        if result is not None: processed.append(result)
            val = result[key]; counts[val] = counts.get(val, 0) + 1

    return processed, counts

