        count = 0
        for rec in valid_records:
            score = _compute_score(rec)
            total_score += score
            count += 1
        avg = total_score / count if count else 0.0
        return {'total_score': total_score, 'average_score': avg, 'count': count}
    valid = [r for r in records if _validate(r)]
    agg = _aggregate(valid)
    return {
        'summary': {
            'total': agg['total_score'],
            'average': agg['average_score'],
            'entries': agg['count']
        },
