def process_items(items: List[Dict[str, Any]], threshold: float) -> Dict[str, Any]:
    def _filter(item: Dict[str, Any]) -> bool:
        try:
            return float(item.get("score", 0)) >= threshold
        except (TypeError, ValueError):
            return False
    def _transform(item: Dict[str, Any]) -> Dict[str, Any]:
        new_item = dict(item)
        new_item["passed"] = _filter(item)
        return new_item
    passed: List[Dict[str, Any]] = []
    failed: List[Dict[str, Any]] = []
    for itm in items:
        if _filter(itm):
            passed.append(_transform(itm))
        else:
            failed.append(_transform(itm))
    return {"passed": passed, "failed": failed, "stats": {"passed": len(passed), "failed": len(failed)}}

import asyncio
from typing import Any, AsyncIterator, Dict, List, Optional, Tuple
async def process_stream(
    stream: AsyncIterator[Dict[str, Any]],
    batch_size: int,
    max_retries: int = 3,
    timeout: float = 2.0,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    attempt: int = 0
    async def _fetch_batch() -> Tuple[List[Dict[str, Any]], Optional[str]]:
        batch: List[Dict[str, Any]] = []
        try:
            for _ in range(batch_size):
                item = await stream.__anext__()
                batch.append(item)
        except StopAsyncIteration:
            return batch, None
        except Exception as exc:
            return [], str(exc)
        return batch, None
    while attempt < max_retries:
        try:
            batch, err = await asyncio.wait_for(_fetch_batch(), timeout=timeout)
            if err:
                errors.append(err)
                attempt += 1
                continue
            if not batch:
                break
            for item in batch:
                if not isinstance(item, dict):
                    errors.append("invalid item type")
                    continue
                processed = {k: v for k, v in item.items() if v is not None}
                results.append(processed)
        except asyncio.TimeoutError:
            errors.append("timeout")
            attempt += 1
    return {
        "results": results,
        "errors": errors,
        "attempts": attempt,
    }

