def compute_statistics(values: List[float], threshold: float = 0.0) -> Tuple[Dict[str, float], List[float]]:

    def _is_above(v: float) -> bool:
        return v > threshold
    above: List[float] = []
    below: List[float] = []
    for v in values:
        if _is_above(v):
            above.append(v)
        else:
            below.append(v)
    def _mean(lst: List[float]) -> float:
        return sum(lst) / len(lst) if lst else 0.0
    stats: Dict[str, float] = {
        "count": len(values),
        "mean": _mean(values),
        "above_mean": _mean(above),
        "below_mean": _mean(below),
        "threshold": threshold,
    }

    return stats, above

