def compute_stats(values: List[float]) -> Dict[str, Optional[float]]:
    if not values:
        return {"count": 0, "mean": None, "min": None, "max": None}
    total = sum(values)
    count = len(values)
    mean = total / count
    min_val = min(values)
    max_val = max(values)
    return {
        "count": count,
        "mean": mean,
        "min": min_val,
        "max": max_val,
    }

