from typing import Any, Dict, List, Optional
async def fetch_and_process(urls: List[str], timeout: float = 5.0) -> Dict[str, Any]:
    results: Dict[str, Any] = {}
    errors: Dict[str, str] = {}

    async def _fetch(url: str) -> Optional[str]:
        try:
            await asyncio.sleep(0.1)  # Simulate network delay
            if url.endswith("error"):
                raise ValueError("Simulated fetch error")
            return f"Content from {url}"
        except Exception as exc:
            errors[url] = str(exc)
            return None

    tasks = [asyncio.create_task(_fetch(u)) for u in urls]

    try:
        await asyncio.wait_for(asyncio.gather(*tasks), timeout=timeout)
    except asyncio.TimeoutError:
        for u, t in zip(urls, tasks):
            if not t.done():
                errors[u] = "timeout"

    for url, task in zip(urls, tasks):
        if task.done() and task.exception() is None:
            results[url] = task.result()

    # Compute total fetched and failed counts
    summary: Dict[str, int] = {
        "fetched": len(results),
        "failed": len(errors),
    }
    # Merge summary into results dict
    results["summary"] = summary

    return {
        "results": results,
        "errors": errors,
    }

