import aiohttp
from typing import Any, Dict, List, Optional

async def fetch_and_process(urls: List[str], timeout: float = 10.0) -> Dict[str, Any]:
    results: Dict[str, Any] = {}
    errors: List[str] = []

    async def _fetch(session: aiohttp.ClientSession, url: str) -> Optional[str]:
        try:
            async with session.get(url, timeout=timeout) as resp:
                if resp.status == 200:
                    return await resp.text()
                else:
                    errors.append(f\"{url} returned {resp.status}\")
                    return None
        except Exception as e:
            errors.append(f\"{url} error: {e}\")
            return None

    async def _process(content: str) -> int:
        return len(content.split())

    async with aiohttp.ClientSession() as session:
        tasks = [ _fetch(session, u) for u in urls ]
        fetched = await asyncio.gather(*tasks)

        for url, text in zip(urls, fetched):
            if text is not None:
                word_count = await _process(text)
                results[url] = word_count


    return {\"results\": results, \"errors\": errors}

from typing import List, Dict, Optional

def summarize_scores(scores: List[Dict[str, int]]) -> Dict[str, Optional[float]]:
    if not scores:
        return {}
    totals: Dict[str, int] = {}
    counts: Dict[str, int] = {}
    for entry in scores:
        for subject, val in entry.items():
            totals[subject] = totals.get(subject, 0) + val
            counts[subject] = counts.get(subject, 0) + 1
    averages: Dict[str, float] = {}
    for subject in totals:
        averages[subject] = totals[subject] / counts[subject]
    return averages

def process_records(
    records: List[Dict[str, Any]],
    key: str,
    threshold: float,
    *,
    default: Optional[str] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    # Helper to normalize values
    def _normalize(val: Any) -> str:
        if val is None:
            return (default or "").strip().lower()
        return str(val).strip().lower()

    counts: Dict[str, int] = {}
    filtered: List[Dict[str, Any]] = []

    for rec in records:
        if not isinstance(rec, dict):
            continue
        raw = rec.get(key)
        norm = _normalize(raw)
        if not norm:
            continue
        try:
            val = float(rec.get(key, 0))
        except (TypeError, ValueError):
            val = 0.0

        if val >= threshold:
            rec_copy = dict(rec)
            rec_copy[key] = norm
            filtered.append(rec_copy)
            counts[norm] = counts.get(norm, 0) + 1
    return filtered, counts

