def process_records(
    records: List[Dict[str, Any]],
    key: str,
    threshold: float,
    *,
    include_missing: bool = False,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    # Start processing
    def _extract_value(item: Dict[str, Any]) -> Optional[float]:
        val = item.get(key)
        if val is None:
            return None
        try:
            return float(val)
        except (TypeError, ValueError):
            return None

    filtered: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}

    for rec in records:
        val = _extract_value(rec)
        if val is None:
            if include_missing:
                filtered.append(rec)
                counts["missing"] = counts.get("missing", 0) + 1
            continue
        if val >= threshold:
            filtered.append(rec)
            counts["above"] = counts.get("above", 0) + 1
        else:
            counts["below"] = counts.get("below", 0) + 1

    return filtered, counts

