def process_data(items: List[Dict[str, str]], threshold: int) -> Tuple[List[Dict[str, str]], Dict[str, int]]:
    def _filter(item: Dict[str, str]) -> bool:
        try:
            return int(item.get("value", 0)) > threshold
        except (ValueError, TypeError):
            return False
    def _transform(item: Dict[str, str]) -> Dict[str, str]:
        new_item = dict(item)
        new_item["value"] = str(int(item.get("value", 0)) * 2)
        return new_item
    filtered = [i for i in items if _filter(i)]
