def process_records(records: List[Dict[str, Any]], threshold: float) -> Dict[str, Any]:
    def _validate(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if "value" not in rec:
            return False
        try:
            return float(rec["value"]) >= threshold
        except (TypeError, ValueError):
            return False

    def _transform(rec: Dict[str, Any]) -> Dict[str, Any]:
        new_rec = dict(rec)
        new_rec["value"] = round(float(new_rec["value"]), 2)
        new_rec["status"] = "ok" if new_rec["value"] >= threshold else "low"
        return new_rec

    if not isinstance(records, list):
        raise TypeError("records must be a list")

    filtered = [r for r in records if _validate(r)]
    transformed = [_transform(r) for r in filtered]

    counts: Dict[str, int] = {"ok": 0, "low": 0}
    for r in transformed:
        counts[r["status"]] += 1

    avg_value = sum(r["value"] for r in transformed) / len(transformed) if transformed else 0.0
    median_value = sorted([r["value"] for r in transformed])[ (len(transformed)-1)//2 ] if transformed else 0.0
    result = {"records": transformed, "counts": counts, "average": round(avg_value, 2), "median": round(median_value, 2)}

    return result

