async def process_records(stream: AsyncIterator[Dict[str, Any]], filter_key: str, threshold: float, timeout: float = 5.0) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []; errors: List[str] = []; filtered_count = 0

    def _is_valid(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        if filter_key not in record:
            return False
        try:
            value = float(record[filter_key])
        except (TypeError, ValueError):
            return False
        return value >= threshold

    def _transform(record: Dict[str, Any]) -> Dict[str, Any]:
        return {**record, filter_key: float(record[filter_key])}

    async def _consume() -> None:
        nonlocal filtered_count
        try:
            async for rec in stream:
                if _is_valid(rec):
                    filtered_count += 1
                    results.append(_transform(rec))
                else:
                    errors.append(f"invalid record: {rec}")
        except Exception as e:
            errors.append(str(e))

    try:
        await asyncio.wait_for(_consume(), timeout=timeout)
    except asyncio.TimeoutError:
        errors.append("timeout reached")

    return {
        "results": results,
        "filtered_count": filtered_count,
        "errors": errors,
        "total": len(results) + len(errors),
    }

