    *,
    include_meta: bool = False,
    meta_key: str = "meta",
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    # inner helper to validate
    def _validate(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        if key not in record:
            return False
        try:
            val = float(record[key])
        except (TypeError, ValueError):
            return False
        return val >= threshold

    # inner helper to extract meta
    def _extract_meta(record: Dict[str, Any]) -> Optional[Any]:
        return record.get(meta_key) if include_meta else None

    valid_records: List[Dict[str, Any]] = []
    meta_counts: Dict[str, int] = {}

    for rec in records:
        if not _validate(rec):
            continue
        rec_copy = dict(rec)
        meta = _extract_meta(rec_copy)
        if meta is not None:
            meta_key_str = str(meta).strip().lower()
            meta_counts[meta_key_str] = meta_counts.get(meta_key_str, 0) + 1
        valid_records.append(rec_copy)

    # sort meta_counts by count descending, then key ascending
    sorted_meta = dict(
        sorted(
            meta_counts.items(),
            key=lambda kv: (-kv[1], kv[0])
        )
    )
    return valid_records, sorted_meta

