    threshold: float,
    *,
    include_missing: bool = False,
    default_value: Optional[Any] = None,
) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]], Dict[str, int]]:
    def _extract_value(rec: Dict[str, Any]) -> Optional[float]:
        val = rec.get(key)
        if val is None:
            return None
        try:
            return float(val)
        except (TypeError, ValueError):
            return None

    def _normalize(rec: Dict[str, Any]) -> Dict[str, Any]:
        new_rec = dict(rec)
        val = _extract_value(rec)
        if val is None:
            new_rec[key] = default_value
        else:
            new_rec[key] = val
        return new_rec

    above: List[Dict[str, Any]] = []; below: List[Dict[str, Any]] = []
    stats: Dict[str, int] = {"above": 0, "below": 0, "missing": 0}

    for rec in records:
        norm_rec = _normalize(rec)
        val = norm_rec.get(key)
        if val is None:
            if include_missing:
                below.append(norm_rec)
                stats["missing"] += 1
            continue
        if val >= threshold:
            above.append(norm_rec)
            stats["above"] += 1
        else:
            below.append(norm_rec)
            stats["below"] += 1
    return above, below, stats

