import asyncio
import aiohttp
async def fetch_lengths(urls: List[str], timeout: float = 5.0) -> Dict[str, Any]:
    results: Dict[str, Any] = {}
    errors: List[str] = []
    async def _fetch(url: str) -> Optional[str]:
        try:
            async with aiohttp.ClientSession() as session:
                async with session.get(url, timeout=timeout) as resp:
                    if resp.status == 200:
                        return await resp.text()
                    errors.append(f"{url} returned {resp.status}")
        except Exception as e:
            errors.append(f"{url} error: {e}")
        return None
    tasks = [asyncio.create_task(_fetch(u)) for u in urls]
    responses = await asyncio.gather(*tasks, return_exceptions=True)
    for url, content in zip(urls, responses):
        if isinstance(content, Exception):
            errors.append(f"{url} exception: {content}")
        elif content is not None:
            results[url] = len(content)
    return {"results": results, "errors": errors}

import asyncio
from typing import Any, AsyncIterator, Dict, List, Optional
async def process_data(
    stream: AsyncIterator[Dict[str, Any]],
    batch_size: int,
    max_retries: int = 3,
) -> Dict[str, Any]:
    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    async def _fetch_batch() -> List[Dict[str, Any]]:
        batch: List[Dict[str, Any]] = []
        try:
            async for _ in range(batch_size):
                item = await stream.__anext__()
                batch.append(item)
        except StopAsyncIteration:
            pass
        return batch
    async def _process_batch(batch: List[Dict[str, Any]]) -> None:
        for item in batch:
            try:
                results.append(item)
            except Exception as e:
                errors.append(str(e))
    async def _retry_fetch(attempt: int) -> List[Dict[str, Any]]:
        try:
            return await _fetch_batch()
        except Exception as e:
            if attempt < max_retries:
                await asyncio.sleep(0.1 * attempt)
                return await _retry_fetch(attempt + 1)
            else:
                errors.append(str(e))
                return []
    while True:
        batch = await _retry_fetch(1)
        if not batch:
            break
        await _process_batch(batch)
    return {
        "processed": results,
        "errors": errors,
    }

from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_data(
    records: Iterable[Dict[str, Any]],
    key: str,
    threshold: float,
    *,
    default: Optional[str] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    def _normalize(value: Any) -> str:
        if value is None:
            return (default or "").strip().lower()
        return str(value).strip().lower()

    def _filter(record: Dict[str, Any]) -> bool:
        try:
            return float(record.get(key, 0)) >= threshold
        except (TypeError, ValueError):
            return False

    filtered: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}

    for rec in records:
        if not isinstance(rec, dict):
            continue
        if not _filter(rec):
            continue
        norm_key = _normalize(rec.get(key))
        if not norm_key:
            continue
        counts[norm_key] = counts.get(norm_key, 0) + 1
        new_rec = dict(rec)
        new_rec[key] = norm_key
        filtered.append(new_rec)

    sorted_counts = dict(sorted(counts.items(), key=lambda kv: (-kv[1], kv[0])))

    return filtered, sorted_counts

from typing import List, Dict, Any


def analyze_numbers(
    numbers: List[int],
    threshold: int = 0,
    *,
    reverse: bool = False
) -> Dict[str, Any]:
    def _is_above(x: int) -> bool:
        return x > threshold

    filtered = [x for x in numbers if _is_above(x)]
    if reverse:
        filtered = list(reversed(filtered))

    count = len(filtered)
    total = sum(filtered)
    avg = total / count if count else 0.0
    return {"filtered": filtered, "count": count, "total": total, "average": avg}

