from typing import Any, Dict, List
async def fetch_and_process(urls: List[str], timeout: float = 5.0) -> Dict[str, Any]:
    results: Dict[str, Any] = {}
    errors: List[str] = []
    async def _fetch(url: str) -> Any:
        try:
            async with aiohttp.ClientSession() as session:
                async with session.get(url, timeout=timeout) as resp:
                    resp.raise_for_status()
                    return await resp.json()
        except Exception as e:
            return {\"error\": str(e)}
    tasks = [asyncio.create_task(_fetch(u)) for u in urls]
    for u, task in zip(urls, tasks):
        try:
            data = await task
            if isinstance(data, dict) and \"error\" not in data:
                results[u] = data
            else:
                errors.append(f\"{u}: {data.get('error', 'unknown error')}\")
        except Exception as e:
            errors.append(f\"{u}: {e}\")
    return {\"results\": results, \"errors\": errors}

