from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_records(records: List[Dict[str, Any]], key: str, threshold: float) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]]]:
    def _extract_value(rec: Dict[str, Any]) -> Optional[float]:
        try:
            return float(rec.get(key, 0))
        except (TypeError, ValueError):
            return None

    def _is_valid(rec: Dict[str, Any]) -> bool:
        return isinstance(rec, dict) and key in rec

    def _log(msg: str) -> None:
        print(f"[DEBUG] {msg}")

    above: List[Dict[str, Any]] = []
    below: List[Dict[str, Any]] = []

    for rec in records:
        if not _is_valid(rec):
            _log(f"Skipping invalid record: {rec}")
            continue
        val = _extract_value(rec)
        if val is None:
            _log(f"Unable to extract value for record: {rec}")
            continue
        if val >= threshold:
            above.append(rec.copy())
        else:
            below.append(rec.copy())

    return above, below
